import { describe, it, expect } from 'vitest';
import fc from 'fast-check';
import { GuildRank } from '@perfect-world/shared';
import { MemberAction } from './dto';

/**
 * Property-Based Tests for Guild Service
 *
 * Validates: Requirements 18.1, 18.3, 18.7
 */

// ─── Pure Logic Extracted for Property Testing ────────────────────────

/**
 * Guild description truncation logic (mirrors guild.service.ts updateSettings)
 * Requirement 18.1: description max 500 characters
 */
function truncateGuildDescription(description: string): string {
  return description.slice(0, 500);
}

/**
 * Guild search filter logic (mirrors guild.service.ts searchGuilds)
 * Requirement 18.3: filters for min level, territory count, recruitment status
 */
interface GuildData {
  id: string;
  name: string;
  memberCount: number;
  territoryCount: number;
  isRecruiting: boolean;
  minLevel: number;
}

interface GuildSearchFilters {
  name?: string;
  minLevel?: number;
  minTerritoryCount?: number;
  isRecruiting?: boolean;
  page?: number;
  pageSize?: number;
}

function filterGuilds(guilds: GuildData[], filters: GuildSearchFilters): GuildData[] {
  let results = [...guilds];

  if (filters.name !== undefined) {
    results = results.filter((g) =>
      g.name.toLowerCase().includes(filters.name!.toLowerCase()),
    );
  }

  if (filters.minLevel !== undefined) {
    results = results.filter((g) => g.minLevel >= filters.minLevel!);
  }

  if (filters.minTerritoryCount !== undefined && filters.minTerritoryCount > 0) {
    results = results.filter((g) => g.territoryCount >= filters.minTerritoryCount!);
  }

  if (filters.isRecruiting !== undefined) {
    results = results.filter((g) => g.isRecruiting === filters.isRecruiting);
  }

  return results;
}

function paginateResults(results: GuildData[], page: number, pageSize: number): GuildData[] {
  const effectivePageSize = Math.min(pageSize, 20);
  const skip = (page - 1) * effectivePageSize;
  return results.slice(skip, skip + effectivePageSize);
}

/**
 * Guild permission check logic (mirrors guild.service.ts manageMember)
 * Requirement 18.7: only guild leader can perform management actions
 */
type ManagementAction = 'PROMOTE' | 'DEMOTE' | 'REMOVE';

interface PermissionCheckResult {
  allowed: boolean;
  error?: string;
}

function checkGuildManagementPermission(
  requesterRank: GuildRank | null,
  action: ManagementAction,
): PermissionCheckResult {
  if (requesterRank !== GuildRank.LEADER) {
    return {
      allowed: false,
      error: 'Insufficient guild rank permissions. Only the guild leader can manage members.',
    };
  }
  return { allowed: true };
}

// ─── Arbitraries ──────────────────────────────────────────────────────

/** Generate an arbitrary string of any length (including very long ones) */
const arbitraryDescription = fc.string({ minLength: 0, maxLength: 2000 });

/** Generate a guild data object */
const guildDataArb: fc.Arbitrary<GuildData> = fc.record({
  id: fc.uuid(),
  name: fc.string({ minLength: 1, maxLength: 100 }),
  memberCount: fc.integer({ min: 1, max: 500 }),
  territoryCount: fc.integer({ min: 0, max: 50 }),
  isRecruiting: fc.boolean(),
  minLevel: fc.integer({ min: 1, max: 150 }),
});

/** Generate a list of guilds */
const guildListArb = fc.array(guildDataArb, { minLength: 0, maxLength: 100 });

/** Generate search filters */
const searchFiltersArb: fc.Arbitrary<GuildSearchFilters> = fc.record({
  name: fc.option(fc.string({ minLength: 1, maxLength: 50 }), { nil: undefined }),
  minLevel: fc.option(fc.integer({ min: 1, max: 150 }), { nil: undefined }),
  minTerritoryCount: fc.option(fc.integer({ min: 0, max: 50 }), { nil: undefined }),
  isRecruiting: fc.option(fc.boolean(), { nil: undefined }),
  page: fc.option(fc.integer({ min: 1, max: 10 }), { nil: undefined }),
  pageSize: fc.option(fc.integer({ min: 1, max: 50 }), { nil: undefined }),
});

/** Generate a non-leader guild rank */
const nonLeaderRankArb: fc.Arbitrary<GuildRank> = fc.constantFrom(
  GuildRank.OFFICER,
  GuildRank.VETERAN,
  GuildRank.MEMBER,
  GuildRank.RECRUIT,
);

/** Generate any guild rank */
const anyRankArb: fc.Arbitrary<GuildRank> = fc.constantFrom(
  GuildRank.LEADER,
  GuildRank.OFFICER,
  GuildRank.VETERAN,
  GuildRank.MEMBER,
  GuildRank.RECRUIT,
);

/** Generate a management action */
const managementActionArb: fc.Arbitrary<ManagementAction> = fc.constantFrom(
  'PROMOTE',
  'DEMOTE',
  'REMOVE',
);

// ─── Property 27: Guild Description Truncation ────────────────────────

describe('Feature: perfect-world-neo-brutalism, Property 27: Guild Description Truncation', () => {
  /**
   * **Validates: Requirements 18.1**
   *
   * For any guild with a description string of arbitrary length, the displayed
   * description SHALL never exceed 500 characters.
   */

  it('truncated description never exceeds 500 characters', () => {
    fc.assert(
      fc.property(arbitraryDescription, (description) => {
        const result = truncateGuildDescription(description);
        expect(result.length).toBeLessThanOrEqual(500);
      }),
      { numRuns: 500 },
    );
  });

  it('descriptions of 500 characters or fewer are preserved exactly', () => {
    const shortDescriptionArb = fc.string({ minLength: 0, maxLength: 500 });

    fc.assert(
      fc.property(shortDescriptionArb, (description) => {
        const result = truncateGuildDescription(description);
        expect(result).toBe(description);
      }),
      { numRuns: 500 },
    );
  });

  it('descriptions longer than 500 characters are truncated to exactly 500', () => {
    const longDescriptionArb = fc.string({ minLength: 501, maxLength: 2000 });

    fc.assert(
      fc.property(longDescriptionArb, (description) => {
        const result = truncateGuildDescription(description);
        expect(result.length).toBe(500);
      }),
      { numRuns: 500 },
    );
  });

  it('truncated description is a prefix of the original', () => {
    fc.assert(
      fc.property(arbitraryDescription, (description) => {
        const result = truncateGuildDescription(description);
        expect(description.startsWith(result)).toBe(true);
      }),
      { numRuns: 500 },
    );
  });
});

// ─── Property 28: Guild Search Filter Correctness ─────────────────────

describe('Feature: perfect-world-neo-brutalism, Property 28: Guild Search Filter Correctness', () => {
  /**
   * **Validates: Requirements 18.3**
   *
   * For any guild search with active filters (minimum level, territory count,
   * recruitment status), all returned results SHALL satisfy every active filter
   * condition, and no guild satisfying all conditions SHALL be excluded from
   * results. Each page SHALL contain at most 20 results.
   */

  it('all returned results satisfy every active filter condition', () => {
    fc.assert(
      fc.property(guildListArb, searchFiltersArb, (guilds, filters) => {
        const results = filterGuilds(guilds, filters);

        for (const guild of results) {
          if (filters.name !== undefined) {
            expect(guild.name.toLowerCase()).toContain(filters.name.toLowerCase());
          }
          if (filters.minLevel !== undefined) {
            expect(guild.minLevel).toBeGreaterThanOrEqual(filters.minLevel);
          }
          if (filters.minTerritoryCount !== undefined && filters.minTerritoryCount > 0) {
            expect(guild.territoryCount).toBeGreaterThanOrEqual(filters.minTerritoryCount);
          }
          if (filters.isRecruiting !== undefined) {
            expect(guild.isRecruiting).toBe(filters.isRecruiting);
          }
        }
      }),
      { numRuns: 500 },
    );
  });

  it('no guild satisfying all conditions is excluded from results', () => {
    fc.assert(
      fc.property(guildListArb, searchFiltersArb, (guilds, filters) => {
        const results = filterGuilds(guilds, filters);

        // Check that every guild in the original list that satisfies all filters is in results
        for (const guild of guilds) {
          let satisfiesAll = true;

          if (filters.name !== undefined) {
            if (!guild.name.toLowerCase().includes(filters.name.toLowerCase())) {
              satisfiesAll = false;
            }
          }
          if (filters.minLevel !== undefined) {
            if (guild.minLevel < filters.minLevel) {
              satisfiesAll = false;
            }
          }
          if (filters.minTerritoryCount !== undefined && filters.minTerritoryCount > 0) {
            if (guild.territoryCount < filters.minTerritoryCount) {
              satisfiesAll = false;
            }
          }
          if (filters.isRecruiting !== undefined) {
            if (guild.isRecruiting !== filters.isRecruiting) {
              satisfiesAll = false;
            }
          }

          if (satisfiesAll) {
            expect(results).toContainEqual(guild);
          }
        }
      }),
      { numRuns: 500 },
    );
  });

  it('each page contains at most 20 results', () => {
    fc.assert(
      fc.property(
        guildListArb,
        fc.integer({ min: 1, max: 10 }),
        fc.integer({ min: 1, max: 50 }),
        (guilds, page, requestedPageSize) => {
          const paginated = paginateResults(guilds, page, requestedPageSize);
          expect(paginated.length).toBeLessThanOrEqual(20);
        },
      ),
      { numRuns: 500 },
    );
  });

  it('page size is capped at 20 regardless of requested size', () => {
    // Generate a large guild list to ensure we have enough data
    const largeGuildListArb = fc.array(guildDataArb, { minLength: 50, maxLength: 100 });

    fc.assert(
      fc.property(
        largeGuildListArb,
        fc.integer({ min: 21, max: 100 }),
        (guilds, requestedPageSize) => {
          const paginated = paginateResults(guilds, 1, requestedPageSize);
          expect(paginated.length).toBeLessThanOrEqual(20);
        },
      ),
      { numRuns: 200 },
    );
  });
});

// ─── Property 29: Guild Permission Enforcement ────────────────────────

describe('Feature: perfect-world-neo-brutalism, Property 29: Guild Permission Enforcement', () => {
  /**
   * **Validates: Requirements 18.7**
   *
   * For any guild member with rank below LEADER attempting a management action
   * (promote, demote, or remove another member), the action SHALL be rejected
   * with a permission error.
   */

  it('non-leader ranks are always rejected for any management action', () => {
    fc.assert(
      fc.property(nonLeaderRankArb, managementActionArb, (rank, action) => {
        const result = checkGuildManagementPermission(rank, action);
        expect(result.allowed).toBe(false);
        expect(result.error).toBeDefined();
        expect(result.error).toContain('guild leader');
      }),
      { numRuns: 200 },
    );
  });

  it('leader rank is always allowed for any management action', () => {
    fc.assert(
      fc.property(managementActionArb, (action) => {
        const result = checkGuildManagementPermission(GuildRank.LEADER, action);
        expect(result.allowed).toBe(true);
        expect(result.error).toBeUndefined();
      }),
      { numRuns: 200 },
    );
  });

  it('null rank (not in guild) is rejected for any management action', () => {
    fc.assert(
      fc.property(managementActionArb, (action) => {
        const result = checkGuildManagementPermission(null, action);
        expect(result.allowed).toBe(false);
        expect(result.error).toBeDefined();
      }),
      { numRuns: 200 },
    );
  });

  it('permission check is deterministic for any rank and action combination', () => {
    fc.assert(
      fc.property(anyRankArb, managementActionArb, (rank, action) => {
        const result1 = checkGuildManagementPermission(rank, action);
        const result2 = checkGuildManagementPermission(rank, action);
        expect(result1.allowed).toBe(result2.allowed);
        expect(result1.error).toBe(result2.error);
      }),
      { numRuns: 200 },
    );
  });

  it('only LEADER rank is allowed - all other ranks are rejected', () => {
    fc.assert(
      fc.property(anyRankArb, managementActionArb, (rank, action) => {
        const result = checkGuildManagementPermission(rank, action);
        if (rank === GuildRank.LEADER) {
          expect(result.allowed).toBe(true);
        } else {
          expect(result.allowed).toBe(false);
        }
      }),
      { numRuns: 200 },
    );
  });
});

import { describe, it, expect } from 'vitest';
import fc from 'fast-check';
import { RankCategory, RANKINGS } from '@perfect-world/shared';
import { RankingService } from './ranking.service';

/**
 * Property-Based Tests for Ranking Service
 *
 * Validates: Requirements 6.1, 6.7, 6.6
 */

// ─── Helpers / Arbitraries ────────────────────────────────────────────

/** The ranking service instance (we only use pure methods) */
const service = Object.create(RankingService.prototype) as RankingService;

/** Generate a RawRankEntry with bigint score and tiebreaker */
const rawRankEntryArb = fc.record({
  entityId: fc.uuid(),
  entityName: fc.string({ minLength: 1, maxLength: 30 }),
  score: fc.bigInt({ min: 0n, max: 1_000_000n }),
  tiebreaker: fc.bigInt({ min: 0n, max: 1_000_000n }),
  metadata: fc.constant(null),
});

/** Generate a list of RawRankEntries */
const rawRankEntryListArb = fc.array(rawRankEntryArb, { minLength: 0, maxLength: 200 });

/** Generate a non-empty list of RawRankEntries */
const nonEmptyRawRankEntryListArb = fc.array(rawRankEntryArb, { minLength: 1, maxLength: 200 });

/** Generate a RankCategory */
const rankCategoryArb = fc.constantFrom(
  RankCategory.TOP_PLAYERS,
  RankCategory.TOP_GUILDS,
  RankCategory.TOP_PVP,
  RankCategory.TOP_ECONOMY,
);

// ─── Property 8: Ranking Sort Order Correctness ───────────────────────

describe('Feature: perfect-world-neo-brutalism, Property 8: Ranking Sort Order Correctness', () => {
  /**
   * **Validates: Requirements 6.1**
   *
   * For any list of entities within a ranking category, the ranking function
   * SHALL produce a list sorted by primary score descending, then by tiebreaker
   * value descending, such that for any two adjacent entries (rank i, rank i+1),
   * entry i has a score >= entry i+1, and if scores are equal, entry i has
   * tiebreaker >= entry i+1.
   */

  it('sorted entries are in descending order by score, then tiebreaker', () => {
    fc.assert(
      fc.property(nonEmptyRawRankEntryListArb, (entries) => {
        const sorted = service.sortEntries(entries);

        // Verify descending order for all adjacent pairs
        for (let i = 0; i < sorted.length - 1; i++) {
          const current = sorted[i];
          const next = sorted[i + 1];

          // Primary score must be >= next
          expect(current.score >= next.score).toBe(true);

          // If scores are equal, tiebreaker must be >= next
          if (current.score === next.score) {
            expect(current.tiebreaker >= next.tiebreaker).toBe(true);
          }
        }
      }),
      { numRuns: 200 },
    );
  });

  it('sorting preserves all original entries (no entries lost or duplicated)', () => {
    fc.assert(
      fc.property(rawRankEntryListArb, (entries) => {
        const sorted = service.sortEntries(entries);

        // Same length
        expect(sorted.length).toBe(entries.length);

        // All original entity IDs are present
        const originalIds = entries.map((e) => e.entityId).sort();
        const sortedIds = sorted.map((e) => e.entityId).sort();
        expect(sortedIds).toEqual(originalIds);
      }),
      { numRuns: 200 },
    );
  });

  it('sorting does not mutate the original array', () => {
    fc.assert(
      fc.property(rawRankEntryListArb, (entries) => {
        const originalCopy = entries.map((e) => ({ ...e }));
        service.sortEntries(entries);

        // Original array should be unchanged
        expect(entries).toEqual(originalCopy);
      }),
      { numRuns: 200 },
    );
  });
});

// ─── Property 9: Tied Rank Position Assignment ────────────────────────

describe('Feature: perfect-world-neo-brutalism, Property 9: Tied Rank Position Assignment', () => {
  /**
   * **Validates: Requirements 6.7**
   *
   * For any set of ranking entries where two or more entries share the same
   * score AND the same tiebreaker value, those entries SHALL be assigned the
   * same rank position, and the next distinct entry SHALL receive a rank
   * position equal to the tied rank plus the count of tied entries (dense
   * ranking with gaps).
   */

  it('entries with same score AND tiebreaker get the same rank', () => {
    fc.assert(
      fc.property(nonEmptyRawRankEntryListArb, rankCategoryArb, (entries, category) => {
        const sorted = service.sortEntries(entries);
        const ranked = service.assignRanks(sorted, category);

        // For any two entries with same score and tiebreaker, rank must be equal
        for (let i = 0; i < ranked.length; i++) {
          for (let j = i + 1; j < ranked.length; j++) {
            if (ranked[i].score === ranked[j].score && ranked[i].tiebreaker === ranked[j].tiebreaker) {
              expect(ranked[i].rank).toBe(ranked[j].rank);
            }
          }
        }
      }),
      { numRuns: 200 },
    );
  });

  it('next distinct entry after a tie gets rank = position (1-indexed)', () => {
    fc.assert(
      fc.property(nonEmptyRawRankEntryListArb, rankCategoryArb, (entries, category) => {
        const sorted = service.sortEntries(entries);
        const ranked = service.assignRanks(sorted, category);

        // For each entry, if it differs from the previous, its rank = its 1-indexed position
        for (let i = 1; i < ranked.length; i++) {
          const prev = ranked[i - 1];
          const curr = ranked[i];

          if (curr.score !== prev.score || curr.tiebreaker !== prev.tiebreaker) {
            // This is a distinct entry; rank should equal position (i + 1)
            expect(curr.rank).toBe(i + 1);
          }
        }
      }),
      { numRuns: 200 },
    );
  });

  it('first entry always has rank 1', () => {
    fc.assert(
      fc.property(nonEmptyRawRankEntryListArb, rankCategoryArb, (entries, category) => {
        const sorted = service.sortEntries(entries);
        const ranked = service.assignRanks(sorted, category);

        expect(ranked[0].rank).toBe(1);
      }),
      { numRuns: 200 },
    );
  });

  it('ranks are non-decreasing', () => {
    fc.assert(
      fc.property(nonEmptyRawRankEntryListArb, rankCategoryArb, (entries, category) => {
        const sorted = service.sortEntries(entries);
        const ranked = service.assignRanks(sorted, category);

        for (let i = 1; i < ranked.length; i++) {
          expect(ranked[i].rank).toBeGreaterThanOrEqual(ranked[i - 1].rank);
        }
      }),
      { numRuns: 200 },
    );
  });

  it('empty input produces empty output', () => {
    fc.assert(
      fc.property(rankCategoryArb, (category) => {
        const ranked = service.assignRanks([], category);
        expect(ranked).toEqual([]);
      }),
      { numRuns: 10 },
    );
  });
});

// ─── Property 11: Pagination Correctness ──────────────────────────────

describe('Feature: perfect-world-neo-brutalism, Property 11: Pagination Correctness', () => {
  /**
   * **Validates: Requirements 6.6**
   *
   * For any total entry count N and page size P, the pagination function SHALL
   * produce exactly ceil(N/P) pages, each page (except possibly the last)
   * containing exactly P entries, and the last page containing between 1 and P
   * entries inclusive.
   */

  /** Generate a list of generic items for pagination testing */
  const itemListArb = fc.array(fc.integer(), { minLength: 0, maxLength: 500 });

  /** Generate a valid page size (use the default 100 and also test other sizes) */
  const pageSizeArb = fc.integer({ min: 1, max: 200 });

  it('totalPages equals ceil(N/P) (minimum 1)', () => {
    fc.assert(
      fc.property(itemListArb, pageSizeArb, (items, pageSize) => {
        const result = service.paginate(items, 1, pageSize);

        const expectedTotalPages = Math.max(1, Math.ceil(items.length / pageSize));
        expect(result.totalPages).toBe(expectedTotalPages);
        expect(result.total).toBe(items.length);
      }),
      { numRuns: 200 },
    );
  });

  it('each full page contains exactly pageSize entries', () => {
    fc.assert(
      fc.property(
        fc.array(fc.integer(), { minLength: 1, maxLength: 500 }),
        pageSizeArb,
        (items, pageSize) => {
          const totalPages = Math.max(1, Math.ceil(items.length / pageSize));

          // Check all pages except the last
          for (let page = 1; page < totalPages; page++) {
            const result = service.paginate(items, page, pageSize);
            expect(result.data.length).toBe(pageSize);
          }
        },
      ),
      { numRuns: 200 },
    );
  });

  it('last page contains between 1 and pageSize entries (for non-empty input)', () => {
    fc.assert(
      fc.property(
        fc.array(fc.integer(), { minLength: 1, maxLength: 500 }),
        pageSizeArb,
        (items, pageSize) => {
          const totalPages = Math.max(1, Math.ceil(items.length / pageSize));
          const lastPage = service.paginate(items, totalPages, pageSize);

          expect(lastPage.data.length).toBeGreaterThanOrEqual(1);
          expect(lastPage.data.length).toBeLessThanOrEqual(pageSize);
        },
      ),
      { numRuns: 200 },
    );
  });

  it('all pages together contain all entries in order', () => {
    fc.assert(
      fc.property(
        fc.array(fc.integer(), { minLength: 0, maxLength: 300 }),
        pageSizeArb,
        (items, pageSize) => {
          const totalPages = Math.max(1, Math.ceil(items.length / pageSize));
          const allData: number[] = [];

          for (let page = 1; page <= totalPages; page++) {
            const result = service.paginate(items, page, pageSize);
            allData.push(...result.data);
          }

          expect(allData).toEqual(items);
        },
      ),
      { numRuns: 200 },
    );
  });

  it('page metadata is correct', () => {
    fc.assert(
      fc.property(
        itemListArb,
        pageSizeArb,
        fc.integer({ min: 1, max: 50 }),
        (items, pageSize, requestedPage) => {
          const result = service.paginate(items, requestedPage, pageSize);

          // Page is clamped to valid range
          const totalPages = Math.max(1, Math.ceil(items.length / pageSize));
          const expectedPage = Math.max(1, Math.min(requestedPage, totalPages));

          expect(result.page).toBe(expectedPage);
          expect(result.pageSize).toBe(pageSize);
          expect(result.total).toBe(items.length);
          expect(result.totalPages).toBe(totalPages);
        },
      ),
      { numRuns: 200 },
    );
  });

  it('empty input produces one page with empty data', () => {
    fc.assert(
      fc.property(pageSizeArb, (pageSize) => {
        const result = service.paginate([], 1, pageSize);

        expect(result.data).toEqual([]);
        expect(result.total).toBe(0);
        expect(result.page).toBe(1);
        expect(result.totalPages).toBe(1);
      }),
      { numRuns: 50 },
    );
  });

  it('default page size of 100 entries per page works correctly', () => {
    fc.assert(
      fc.property(
        fc.array(fc.integer(), { minLength: 101, maxLength: 500 }),
        (items) => {
          const result = service.paginate(items, 1, RANKINGS.PAGE_SIZE);

          expect(result.data.length).toBe(RANKINGS.PAGE_SIZE);
          expect(result.pageSize).toBe(100);
        },
      ),
      { numRuns: 50 },
    );
  });
});

import {
  WebSocketGateway,
  WebSocketServer,
  SubscribeMessage,
  OnGatewayConnection,
  OnGatewayDisconnect,
  OnGatewayInit,
  ConnectedSocket,
  MessageBody,
} from '@nestjs/websockets';
import { Logger, UnauthorizedException } from '@nestjs/common';
import { JwtService } from '@nestjs/jwt';
import { Server, Socket } from 'socket.io';
import { NotificationService } from './notification.service';
import { SocketChannel, VALID_CHANNELS } from './dto/channels.enum';
import { JwtPayload } from '../common/guards/jwt-auth.guard';

interface AuthenticatedSocket extends Socket {
  user?: JwtPayload;
}

@WebSocketGateway({
  cors: {
    origin: process.env.CORS_ORIGINS?.split(',') || ['http://localhost:3000'],
    credentials: true,
  },
  namespace: '/',
  transports: ['websocket', 'polling'],
})
export class NotificationGateway
  implements OnGatewayInit, OnGatewayConnection, OnGatewayDisconnect
{
  @WebSocketServer()
  server!: Server;

  private readonly logger = new Logger(NotificationGateway.name);

  constructor(
    private readonly jwtService: JwtService,
    private readonly notificationService: NotificationService,
  ) {}

  afterInit(server: Server): void {
    this.logger.log('Notification WebSocket Gateway initialized');

    // Apply JWT authentication middleware on handshake
    server.use(async (socket: AuthenticatedSocket, next) => {
      try {
        const token = this.extractToken(socket);

        if (!token) {
          return next(
            new UnauthorizedException(
              'Authentication failed: No token provided',
            ),
          );
        }

        const payload = await this.jwtService.verifyAsync<JwtPayload>(token);
        socket.user = payload;
        next();
      } catch (error) {
        const message =
          error instanceof Error ? error.message : 'Unknown error';
        this.logger.warn(
          `WebSocket authentication failed: ${message}`,
        );
        next(
          new UnauthorizedException(
            `Authentication failed: Invalid or expired JWT token`,
          ),
        );
      }
    });
  }

  handleConnection(client: AuthenticatedSocket): void {
    const userId = client.user?.sub;
    this.logger.log(
      `Client connected: ${client.id} (user: ${userId || 'unknown'})`,
    );

    // Automatically join the user's personal notification room
    if (userId) {
      const personalRoom = this.notificationService.getRoomName(
        SocketChannel.PERSONAL_NOTIFICATIONS,
        userId,
      );
      client.join(personalRoom);
      this.logger.debug(
        `Client ${client.id} auto-joined personal room: ${personalRoom}`,
      );
    }
  }

  handleDisconnect(client: AuthenticatedSocket): void {
    const userId = client.user?.sub;
    this.logger.log(
      `Client disconnected: ${client.id} (user: ${userId || 'unknown'})`,
    );
  }

  /**
   * Handles channel subscription requests from clients.
   * Clients can subscribe to: server-status, marketplace-updates,
   * guild-events, territory-war, personal-notifications
   */
  @SubscribeMessage('subscribe')
  handleSubscribe(
    @ConnectedSocket() client: AuthenticatedSocket,
    @MessageBody() data: { channels: string[] },
  ): { event: string; data: { subscribed: string[]; invalid: string[] } } {
    const { channels } = data;

    if (!channels || !Array.isArray(channels)) {
      return {
        event: 'subscribe:error',
        data: { subscribed: [], invalid: [] },
      };
    }

    const { valid, invalid } =
      this.notificationService.validateChannels(channels);

    // Join valid channel rooms
    for (const channel of valid) {
      const roomName = this.notificationService.getRoomName(
        channel,
        client.user?.sub,
      );
      client.join(roomName);
      this.logger.debug(`Client ${client.id} subscribed to: ${roomName}`);
    }

    if (invalid.length > 0) {
      this.logger.warn(
        `Client ${client.id} attempted to subscribe to invalid channels: ${invalid.join(', ')}`,
      );
    }

    return {
      event: 'subscribe:success',
      data: { subscribed: valid, invalid },
    };
  }

  /**
   * Handles channel unsubscription requests from clients.
   */
  @SubscribeMessage('unsubscribe')
  handleUnsubscribe(
    @ConnectedSocket() client: AuthenticatedSocket,
    @MessageBody() data: { channels: string[] },
  ): { event: string; data: { unsubscribed: string[] } } {
    const { channels } = data;

    if (!channels || !Array.isArray(channels)) {
      return {
        event: 'unsubscribe:error',
        data: { unsubscribed: [] },
      };
    }

    const { valid } = this.notificationService.validateChannels(channels);

    for (const channel of valid) {
      const roomName = this.notificationService.getRoomName(
        channel,
        client.user?.sub,
      );
      client.leave(roomName);
      this.logger.debug(`Client ${client.id} unsubscribed from: ${roomName}`);
    }

    return {
      event: 'unsubscribe:success',
      data: { unsubscribed: valid },
    };
  }

  /**
   * Broadcasts an event to all clients subscribed to a specific channel.
   * Used internally by other services to push realtime updates.
   */
  broadcastToChannel(channel: SocketChannel, event: string, data: unknown): void {
    const roomName = this.notificationService.getRoomName(channel);
    this.server.to(roomName).emit(event, {
      channel,
      data,
      timestamp: new Date().toISOString(),
    });
    this.logger.debug(`Broadcast "${event}" to channel "${channel}"`);
  }

  /**
   * Sends a notification to a specific user's personal channel.
   */
  sendToUser(userId: string, event: string, data: unknown): void {
    const roomName = this.notificationService.getRoomName(
      SocketChannel.PERSONAL_NOTIFICATIONS,
      userId,
    );
    this.server.to(roomName).emit(event, {
      channel: SocketChannel.PERSONAL_NOTIFICATIONS,
      data,
      timestamp: new Date().toISOString(),
    });
    this.logger.debug(`Sent "${event}" to user "${userId}"`);
  }

  /**
   * Extracts the JWT token from the socket handshake.
   * Supports both auth.token and Authorization header.
   */
  private extractToken(socket: Socket): string | undefined {
    // Check auth object (Socket.IO auth option)
    const authToken = socket.handshake.auth?.token;
    if (authToken) {
      return authToken;
    }

    // Check Authorization header
    const authHeader = socket.handshake.headers?.authorization;
    if (authHeader) {
      const [type, token] = authHeader.split(' ');
      if (type === 'Bearer' && token) {
        return token;
      }
    }

    // Check query parameter (fallback)
    const queryToken = socket.handshake.query?.token;
    if (typeof queryToken === 'string') {
      return queryToken;
    }

    return undefined;
  }
}

import { Injectable, Logger } from '@nestjs/common';
import { RedisService } from '../redis/redis.service';
import { SocketChannel, VALID_CHANNELS } from './dto/channels.enum';
import { NotificationEventDto } from './dto/notification-event.dto';

@Injectable()
export class NotificationService {
  private readonly logger = new Logger(NotificationService.name);

  constructor(private readonly redis: RedisService) {}

  /**
   * Validates that the provided channels are all valid SocketChannel values.
   */
  validateChannels(channels: string[]): { valid: string[]; invalid: string[] } {
    const valid = channels.filter((ch) => VALID_CHANNELS.includes(ch));
    const invalid = channels.filter((ch) => !VALID_CHANNELS.includes(ch));
    return { valid, invalid };
  }

  /**
   * Publishes a notification event to a specific channel via Redis pub/sub.
   * This allows the gateway to broadcast to all subscribed clients.
   */
  async publishToChannel(
    channel: SocketChannel,
    event: string,
    data: unknown,
  ): Promise<void> {
    const payload: NotificationEventDto = {
      channel,
      event,
      data,
      timestamp: new Date().toISOString(),
    };

    await this.redis.publish(`channel:${channel}`, JSON.stringify(payload));
    this.logger.debug(`Published event "${event}" to channel "${channel}"`);
  }

  /**
   * Publishes a personal notification to a specific user's channel.
   */
  async publishToUser(
    userId: string,
    event: string,
    data: unknown,
  ): Promise<void> {
    const payload: NotificationEventDto = {
      channel: SocketChannel.PERSONAL_NOTIFICATIONS,
      event,
      data,
      timestamp: new Date().toISOString(),
    };

    await this.redis.publish(
      `channel:notifications:${userId}`,
      JSON.stringify(payload),
    );
    this.logger.debug(`Published personal notification to user "${userId}"`);
  }

  /**
   * Gets the room name for a given channel and optional context (e.g., userId for personal).
   */
  getRoomName(channel: string, userId?: string): string {
    if (channel === SocketChannel.PERSONAL_NOTIFICATIONS && userId) {
      return `${channel}:${userId}`;
    }
    return channel;
  }
}

import { IoAdapter } from '@nestjs/platform-socket.io';
import { Server as SocketIOServer } from 'socket.io';
import { createAdapter } from '@socket.io/redis-adapter';
import Redis from 'ioredis';

/**
 * Redis adapter for Socket.IO to enable pub/sub across multiple server instances.
 * This allows messages published to Redis channels to be broadcast to all connected clients
 * across all server instances.
 */
export class RedisIoAdapter extends IoAdapter {
  private adapterConstructor: ReturnType<typeof createAdapter> | null = null;

  constructor(private redisClient: Redis) {
    super();
  }

  createIOServer(port: number, options?: any): SocketIOServer {
    const server = super.createIOServer(port, options);

    // Create a second Redis client for the pub channel
    const pubClient = this.redisClient.duplicate();
    const subClient = this.redisClient.duplicate();

    // Create and attach the Redis adapter
    this.adapterConstructor = createAdapter(pubClient, subClient);
    server.adapter(this.adapterConstructor);

    return server;
  }
}

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { NotificationGateway } from './notification.gateway';
