/**
 * Integration tests for the Notification Service with Socket.IO
 * These tests verify that the service meets all requirements from Requirement 15
 */

describe('Notification Service Integration Tests', () => {
  let gateway: NotificationGateway;
  let service: NotificationService;

  beforeEach(() => {
    // Mock Redis service
    const mockRedis = {
      publish: vi.fn().mockResolvedValue(1),
      duplicate: vi.fn().mockReturnThis(),
    };

    // Mock JWT service
    const mockJwtService = {
      verifyAsync: vi.fn(),
      sign: vi.fn(),
      signAsync: vi.fn(),
    };

    service = new NotificationService(mockRedis as any);
    gateway = new NotificationGateway(mockJwtService as any, service);

    // Mock server
    gateway.server = {
      use: vi.fn(),
      to: vi.fn().mockReturnValue({ emit: vi.fn() }),
      adapter: vi.fn(),
    } as any;
  });

  describe('Requirement 15.1: WebSocket Connection Establishment', () => {
    it('should establish a Socket.IO websocket connection for authenticated users', () => {
      const mockSocket = {
        id: 'socket-1',
        user: { sub: 'user-123', email: 'test@example.com', role: 'PLAYER' },
        join: vi.fn(),
      };

      gateway.handleConnection(mockSocket as any);

      expect(mockSocket.join).toHaveBeenCalled();
    });

    it('should auto-join user to personal notification room on connection', () => {
      const mockSocket = {
        id: 'socket-1',
        user: { sub: 'user-123', email: 'test@example.com', role: 'PLAYER' },
        join: vi.fn(),
      };

      gateway.handleConnection(mockSocket as any);

      const roomName = service.getRoomName(
        SocketChannel.PERSONAL_NOTIFICATIONS,
        'user-123',
      );
      expect(mockSocket.join).toHaveBeenCalledWith(roomName);
    });
  });

  describe('Requirement 15.3: Channel Subscription', () => {
    it('should support subscription to all valid channels', () => {
      const validChannels = [
        'server-status',
        'marketplace-updates',
        'guild-events',
        'territory-war',
        'personal-notifications',
      ];

      const result = service.validateChannels(validChannels);

      expect(result.valid).toEqual(validChannels);
      expect(result.invalid).toEqual([]);
    });

    it('should deliver messages to subscribed channels', async () => {
      await service.publishToChannel(
        SocketChannel.SERVER_STATUS,
        'status-update',
        { serverId: 'srv-1', status: 'online' },
      );

      // Verify Redis publish was called
      expect(service['redis'].publish).toHaveBeenCalledWith(
        'channel:server-status',
        expect.any(String),
      );
    });

    it('should deliver personal notifications to specific users', async () => {
      await service.publishToUser('user-123', 'notification', {
        title: 'Test',
        body: 'Test body',
      });

      expect(service['redis'].publish).toHaveBeenCalledWith(
        'channel:notifications:user-123',
        expect.any(String),
      );
    });
  });

  describe('Requirement 15.5: JWT Authentication', () => {
    it('should authenticate websocket connections using JWT tokens', () => {
      const mockServer = {
        use: vi.fn(),
        to: vi.fn().mockReturnValue({ emit: vi.fn() }),
        adapter: vi.fn(),
      };

      gateway.afterInit(mockServer as any);

      // Verify that authentication middleware was registered
      expect(mockServer.use).toHaveBeenCalledWith(expect.any(Function));
    });
  });

  describe('Requirement 15.6: Authentication Failure Handling', () => {
    it('should reject connections with invalid JWT tokens', async () => {
      const mockJwtService = {
        verifyAsync: vi.fn().mockRejectedValue(new Error('jwt expired')),
      };

      const mockServer = {
        use: vi.fn(),
        to: vi.fn().mockReturnValue({ emit: vi.fn() }),
        adapter: vi.fn(),
      };

      gateway = new NotificationGateway(mockJwtService as any, service);
      gateway.afterInit(mockServer as any);

      const middleware = mockServer.use.mock.calls[0][0];
      const mockSocket = {
        handshake: {
          auth: { token: 'invalid-token' },
          headers: {},
          query: {},
        },
      };
      const next = vi.fn();

      await middleware(mockSocket, next);

      // Verify that next was called with an error
      expect(next).toHaveBeenCalledWith(expect.any(Error));
    });

    it('should reject connections without a token', async () => {
      const mockJwtService = {
        verifyAsync: vi.fn(),
      };

      const mockServer = {
        use: vi.fn(),
        to: vi.fn().mockReturnValue({ emit: vi.fn() }),
        adapter: vi.fn(),
      };

      gateway = new NotificationGateway(mockJwtService as any, service);
      gateway.afterInit(mockServer as any);

      const middleware = mockServer.use.mock.calls[0][0];
      const mockSocket = {
        handshake: {
          auth: {},
          headers: {},
          query: {},
        },
      };
      const next = vi.fn();

      await middleware(mockSocket, next);

      // Verify that next was called with an error
      expect(next).toHaveBeenCalledWith(expect.any(Error));
    });
  });

  describe('Message Delivery Timing', () => {
    it('should publish messages with timestamps', async () => {
      const beforeTime = new Date().getTime();

      await service.publishToChannel(
        SocketChannel.SERVER_STATUS,
        'test-event',
        { data: 'test' },
      );

      const afterTime = new Date().getTime();

      const publishCall = service['redis'].publish.mock.calls[0];
      const payload = JSON.parse(publishCall[1]);

      expect(payload.timestamp).toBeDefined();
      const payloadTime = new Date(payload.timestamp).getTime();
      expect(payloadTime).toBeGreaterThanOrEqual(beforeTime);
      expect(payloadTime).toBeLessThanOrEqual(afterTime);
    });
  });

  describe('Channel Validation', () => {
    it('should reject invalid channel names', () => {
      const result = service.validateChannels([
        'server-status',
        'invalid-channel',
        'marketplace-updates',
      ]);

      expect(result.valid).toEqual(['server-status', 'marketplace-updates']);
      expect(result.invalid).toEqual(['invalid-channel']);
    });

    it('should handle empty channel list', () => {
      const result = service.validateChannels([]);

      expect(result.valid).toEqual([]);
      expect(result.invalid).toEqual([]);
    });
  });

  describe('Room Management', () => {
    it('should generate correct room names for channels', () => {
      expect(service.getRoomName('server-status')).toBe('server-status');
      expect(service.getRoomName('marketplace-updates')).toBe(
        'marketplace-updates',
      );
    });

    it('should generate user-specific room names for personal notifications', () => {
      const roomName = service.getRoomName(
        'personal-notifications',
        'user-123',
      );
      expect(roomName).toBe('personal-notifications:user-123');
    });
  });
});

import {
  Injectable,
  BadRequestException,
  NotFoundException,
} from '@nestjs/common';
import { DatabaseService } from '../database/database.service';
import { CreateTicketDto } from './dto';
import { SUPPORT } from '@perfect-world/shared';

@Injectable()
export class SupportService {
  constructor(private readonly db: DatabaseService) {}

  /**
   * Create a support ticket.
   * Supports both authenticated (userId provided) and unauthenticated (email required) submissions.
   * Requirement 19.1: category, subject (max 150), description (max 2000), attachments (max 3, max 5MB each)
   * Requirement 19.2: confirm with unique reference number
   * Requirement 19.6: unauthenticated submission with email
   */
  async createTicket(
    dto: CreateTicketDto,
    userId?: string,
  ): Promise<{
    id: string;
    reference: string;
    category: string;
    subject: string;
    description: string;
    status: string;
    email: string;
    createdAt: string;
    attachments: Array<{
      id: string;
      filename: string;
      url: string;
      size: number;
    }>;
  }> {
    // For unauthenticated submissions, email is required
    if (!userId && !dto.email) {
      throw new BadRequestException(
        'Email is required for unauthenticated ticket submissions',
      );
    }

    // Validate attachments
    if (dto.attachments && dto.attachments.length > SUPPORT.MAX_ATTACHMENTS) {
      throw new BadRequestException(
        `Maximum ${SUPPORT.MAX_ATTACHMENTS} attachments allowed`,
      );
    }

    if (dto.attachments) {
      for (const attachment of dto.attachments) {
        if (attachment.size > SUPPORT.MAX_ATTACHMENT_SIZE_BYTES) {
          throw new BadRequestException(
            `Attachment "${attachment.filename}" exceeds the maximum size of 5MB`,
          );
        }
      }
    }

    // Determine email: use user's email if authenticated, otherwise use provided email
    let email = dto.email;
    if (userId && !email) {
      const user = await this.db.user.findUnique({
        where: { id: userId },
        select: { email: true },
      });
      if (user) {
        email = user.email;
      }
    }

    if (!email) {
      throw new BadRequestException('Email is required');
    }

    // Generate unique reference number
    const reference = this.generateReference();

    // Create the ticket with attachments in a transaction
    const ticket = await this.db.$transaction(async (tx) => {
      const createdTicket = await tx.supportTicket.create({
        data: {
          userId: userId || null,
          email,
          category: dto.category,
          subject: dto.subject,
          description: dto.description,
          reference,
          attachments: dto.attachments
            ? {
                create: dto.attachments.map((a) => ({
                  filename: a.filename,
                  url: a.url,
                  size: a.size,
                })),
              }
            : undefined,
        },
        include: {
          attachments: true,
        },
      });

      return createdTicket;
    });

    return {
      id: ticket.id,
      reference: ticket.reference,
      category: ticket.category,
      subject: ticket.subject,
      description: ticket.description,
      status: ticket.status,
      email: ticket.email,
      createdAt: ticket.createdAt.toISOString(),
      attachments: ticket.attachments.map((a) => ({
        id: a.id,
        filename: a.filename,
        url: a.url,
        size: a.size,
      })),
    };
  }

  /**
   * Get tickets for an authenticated user (up to 50 most recent)
   * Requirement 19.5: display reference, subject, category, date, status
   */
  async getTicketsByUser(
    userId: string,
    page: number = 1,
  ): Promise<{
    data: Array<{
      id: string;
      reference: string;
      category: string;
      subject: string;
      status: string;
      createdAt: string;
      updatedAt: string;
    }>;
    total: number;
    page: number;
    pageSize: number;
    totalPages: number;
  }> {
    const pageSize = 50;
    const skip = (page - 1) * pageSize;

    const [tickets, total] = await Promise.all([
      this.db.supportTicket.findMany({
        where: { userId },
        orderBy: { createdAt: 'desc' },
        take: pageSize,
        skip,
        include: {
          attachments: true,
        },
      }),
      this.db.supportTicket.count({ where: { userId } }),
    ]);

    return {
      data: tickets.map((t) => ({
        id: t.id,
        reference: t.reference,
        category: t.category,
        subject: t.subject,
        status: t.status,
        createdAt: t.createdAt.toISOString(),
        updatedAt: t.updatedAt.toISOString(),
      })),
      total,
      page,
      pageSize,
      totalPages: Math.ceil(total / pageSize),
    };
  }

  /**
   * Get a single ticket by reference number
   * Requirement 19.2: retrieve ticket by reference
   */
  async getTicketByReference(
    reference: string,
    userId?: string,
  ): Promise<{
    id: string;
    reference: string;
    userId: string | null;
    email: string;
    category: string;
    subject: string;
    description: string;
    status: string;
    createdAt: string;
    updatedAt: string;
    attachments: Array<{
      id: string;
      filename: string;
      url: string;
      size: number;
    }>;
  }> {
    const where: Record<string, unknown> = { reference };

    // If userId is provided, ensure the ticket belongs to the user
    if (userId) {
      where.userId = userId;
    }

    const ticket = await this.db.supportTicket.findFirst({
      where,
      include: {
        attachments: true,
      },
    });

    if (!ticket) {
      throw new NotFoundException('Ticket not found');
    }

    return {
      id: ticket.id,
      reference: ticket.reference,
      userId: ticket.userId,
      email: ticket.email,
      category: ticket.category,
      subject: ticket.subject,
      description: ticket.description,
      status: ticket.status,
      createdAt: ticket.createdAt.toISOString(),
      updatedAt: ticket.updatedAt.toISOString(),
      attachments: ticket.attachments.map((a) => ({
        id: a.id,
        filename: a.filename,
        url: a.url,
        size: a.size,
      })),
    };
  }

  /**
   * Generate a unique human-readable ticket reference number.
   * Format: PW-YYYYMMDD-XXXXX (e.g., PW-20240115-A3F7K)
   * Requirement 19.2
   */
  generateReference(): string {
    const now = new Date();
    const year = now.getFullYear();
    const month = String(now.getMonth() + 1).padStart(2, '0');
    const day = String(now.getDate()).padStart(2, '0');
    const datePart = `${year}${month}${day}`;

    // Generate a 5-character alphanumeric random suffix
    const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789'; // Exclude confusing chars (0, O, 1, I)
    let suffix = '';
    for (let i = 0; i < 5; i++) {
      suffix += chars.charAt(Math.floor(Math.random() * chars.length));
    }

    return `PW-${datePart}-${suffix}`;
  }
}

import {
  Controller,
  Get,
  Post,
  Param,
  Query,
  Body,
  UseGuards,
  Request,
} from '@nestjs/common';
import { SupportService } from './support.service';
import { CreateTicketDto } from './dto';
import { JwtAuthGuard } from '../common/guards/jwt-auth.guard';
import { Public } from '../common/decorators/public.decorator';
import type { JwtPayload } from '../common/guards/jwt-auth.guard';

@Controller('support')
@UseGuards(JwtAuthGuard)
export class SupportController {
  constructor(private readonly supportService: SupportService) {}

  /**
   * POST /api/support/tickets
   * Create a support ticket. Supports both authenticated and unauthenticated submissions.
   * For unauthenticated submissions, email field is required.
   * Requirements 19.1, 19.2, 19.6
   */
  @Post('tickets')
  @Public()
  async createTicket(
    @Body() dto: CreateTicketDto,
    @Request() req: { user?: JwtPayload },
  ): Promise<{
    id: string;
    reference: string;
    category: string;
    subject: string;
    description: string;
    status: string;
    email: string;
    createdAt: string;
    attachments: Array<{
      id: string;
      filename: string;
      url: string;
      size: number;
    }>;
  }> {
    const userId = req.user?.sub;
    return this.supportService.createTicket(dto, userId);
  }

  /**
   * GET /api/support/tickets
   * Get tickets for the authenticated user (up to 50 most recent)
   * Requirement 19.5
   */
  @Get('tickets')
  async getMyTickets(
    @Request() req: { user: JwtPayload },
    @Query('page') page?: string,
  ): Promise<{
    data: Array<{
      id: string;
      reference: string;
      category: string;
      subject: string;
      status: string;
      createdAt: string;
      updatedAt: string;
    }>;
    total: number;
    page: number;
    pageSize: number;
    totalPages: number;
  }> {
    const pageNum = page ? parseInt(page, 10) : 1;
    return this.supportService.getTicketsByUser(req.user.sub, pageNum);
  }

  /**
   * GET /api/support/tickets/:reference
   * Get a single ticket by reference number.
   * Authenticated users can only see their own tickets.
   * Requirement 19.2, 19.5
   */
  @Get('tickets/:reference')
  async getTicketByReference(
    @Param('reference') reference: string,
    @Request() req: { user: JwtPayload },
  ): Promise<{
    id: string;
    reference: string;
    userId: string | null;
    email: string;
    category: string;
