'use client';

import React, {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useState,
} from 'react';
import { neoBrutalism } from '../styles/tokens';
import type { ThemeContextValue, ThemeMode } from '../types';

const STORAGE_KEY = 'pw-theme-mode';
const VALID_MODES: ThemeMode[] = ['dark', 'light'];
const DEFAULT_MODE: ThemeMode = 'dark';

/**
 * Reads the persisted theme mode from localStorage.
 * Returns the default ('dark') if localStorage is unavailable or the value is invalid.
 */
function getPersistedMode(): ThemeMode {
  try {
    const stored = localStorage.getItem(STORAGE_KEY);
    if (stored && VALID_MODES.includes(stored as ThemeMode)) {
      return stored as ThemeMode;
    }
  } catch {
    // localStorage unavailable (SSR, private browsing, etc.)
  }
  return DEFAULT_MODE;
}

/**
 * Persists the theme mode to localStorage.
 * Silently fails if localStorage is unavailable.
 */
function persistMode(mode: ThemeMode): void {
  try {
    localStorage.setItem(STORAGE_KEY, mode);
  } catch {
    // Silently ignore write failures
  }
}

const ThemeContext = createContext<ThemeContextValue | null>(null);

export interface ThemeProviderProps {
  /** Optional initial mode override (useful for SSR or testing) */
  defaultMode?: ThemeMode;
  children: React.ReactNode;
}

/**
 * ThemeProvider
 *
 * Provides dark/light mode switching with localStorage persistence.
 * Falls back to dark mode if localStorage is unavailable or the stored value is invalid.
 *
 * For flicker-free theme application within 50ms of page render start,
 * include the ThemeInitScript in your document <head>.
 *
 * @see Requirements 1.5, 1.6, 1.7, 1.8
 */
export function ThemeProvider({ defaultMode, children }: ThemeProviderProps) {
  const [mode, setModeState] = useState<ThemeMode>(
    () => defaultMode ?? getPersistedMode()
  );

  const setMode = useCallback((newMode: ThemeMode) => {
    if (!VALID_MODES.includes(newMode)) return;
    setModeState(newMode);
    persistMode(newMode);
    applyModeToDocument(newMode);
  }, []);

  const toggleMode = useCallback(() => {
    setModeState((prev) => {
      const next: ThemeMode = prev === 'dark' ? 'light' : 'dark';
      persistMode(next);
      applyModeToDocument(next);
      return next;
    });
  }, []);

  const colors = useMemo(() => neoBrutalism.colors[mode], [mode]);

  // Apply mode to document on mount (client-side hydration)
  useEffect(() => {
    applyModeToDocument(mode);
  }, [mode]);

  const value: ThemeContextValue = useMemo(
    () => ({ mode, setMode, toggleMode, colors }),
    [mode, setMode, toggleMode, colors]
  );

  return (
    <ThemeContext.Provider value={value}>{children}</ThemeContext.Provider>
  );
}

/**
 * useTheme hook
 *
 * Returns the current theme context including mode, setMode, toggleMode, and colors.
 * Must be used within a ThemeProvider.
 */
export function useTheme(): ThemeContextValue {
  const context = useContext(ThemeContext);
  if (!context) {
    throw new Error('useTheme must be used within a ThemeProvider');
  }
  return context;
}

/**
 * Applies the theme mode to the document element as a data attribute.
 * This enables CSS selectors like [data-theme="dark"] for styling.
 */
function applyModeToDocument(mode: ThemeMode): void {
  if (typeof document !== 'undefined') {
    document.documentElement.setAttribute('data-theme', mode);
    document.documentElement.classList.remove('dark', 'light');
    document.documentElement.classList.add(mode);
  }
}

/**
 * Blocking script content for <head> injection.
 *
 * This script runs synchronously before first paint to read the persisted theme
 * from localStorage and apply it to the document element, preventing flash of
 * wrong theme (FOWT). Ensures theme is applied within 50ms of page render start.
 *
 * Usage in Next.js layout:
 * ```tsx
 * <head>
 *   <script dangerouslySetInnerHTML={{ __html: themeInitScript }} />
 * </head>
 * ```
 *
 * @see Requirement 1.7
 */
export const themeInitScript = `(function(){try{var t=localStorage.getItem('${STORAGE_KEY}');if(t!=='dark'&&t!=='light')t='light';document.documentElement.setAttribute('data-theme',t);document.documentElement.classList.add(t)}catch(e){document.documentElement.setAttribute('data-theme','light');document.documentElement.classList.add('light')}})();`;

import { describe, it, expect, beforeEach, vi } from 'vitest';
import React from 'react';
import { renderHook, act } from '@testing-library/react';
import fc from 'fast-check';
import { ThemeProvider, useTheme } from './ThemeProvider';
import type { ThemeMode } from '../types';

/**
 * Property-Based Tests for Theme Persistence Round-Trip
 *
 * **Validates: Requirements 1.7, 1.8**
 *
 * Property 2: Theme Persistence Round-Trip
 * For any valid theme mode value ('dark' or 'light'), persisting it to storage
 * and then reading it back SHALL return the identical mode value. Additionally,
 * for any invalid or missing storage value, the system SHALL return 'dark' as
 * the default.
 */

// ─── localStorage Mock ────────────────────────────────────────────────

const createLocalStorageMock = () => {
  let store: Record<string, string> = {};
  let shouldThrow = false;

  return {
    getItem: vi.fn((key: string) => {
      if (shouldThrow) throw new Error('localStorage unavailable');
      return store[key] ?? null;
    }),
    setItem: vi.fn((key: string, value: string) => {
      if (shouldThrow) throw new Error('localStorage unavailable');
      store[key] = value;
    }),
    removeItem: vi.fn((key: string) => {
      if (shouldThrow) throw new Error('localStorage unavailable');
      delete store[key];
    }),
    clear: vi.fn(() => {
      store = {};
    }),
    get length() {
      return Object.keys(store).length;
    },
    key: vi.fn((index: number) => Object.keys(store)[index] ?? null),
    _setThrowMode: (shouldThrowMode: boolean) => {
      shouldThrow = shouldThrowMode;
    },
    _getStore: () => store,
  };
};

let localStorageMock = createLocalStorageMock();
Object.defineProperty(window, 'localStorage', { value: localStorageMock, writable: true });

// ─── Helpers ──────────────────────────────────────────────────────────

const STORAGE_KEY = 'pw-theme-mode';
const VALID_MODES: ThemeMode[] = ['dark', 'light'];

function wrapper({ children }: { children: React.ReactNode }) {
  return <ThemeProvider>{children}</ThemeProvider>;
}

// ─── Arbitraries ──────────────────────────────────────────────────────

/** Generates a valid theme mode ('dark' or 'light') */
const validModeArb = fc.constantFrom<ThemeMode>('dark', 'light');

/** Generates an arbitrary string that is NOT 'dark' or 'light' */
const invalidModeArb = fc
  .string({ minLength: 0, maxLength: 50 })
  .filter((s) => s !== 'dark' && s !== 'light');

// ─── Property Tests ───────────────────────────────────────────────────

describe('Feature: perfect-world-neo-brutalism, Property 2: Theme Persistence Round-Trip', () => {
  beforeEach(() => {
    localStorageMock = createLocalStorageMock();
    Object.defineProperty(window, 'localStorage', { value: localStorageMock, writable: true });
    vi.clearAllMocks();
    document.documentElement.removeAttribute('data-theme');
    document.documentElement.classList.remove('dark', 'light');
  });

  it('for any valid mode, storing and retrieving returns the same mode', () => {
    /**
     * **Validates: Requirements 1.7**
     *
     * For any valid theme mode ('dark' or 'light'), persisting it to localStorage
     * via setMode and then reading it back on a fresh mount returns the same value.
     */
    fc.assert(
      fc.property(validModeArb, (mode) => {
        // Reset state
        localStorageMock.clear();
        document.documentElement.removeAttribute('data-theme');
        document.documentElement.classList.remove('dark', 'light');

        // Persist the mode via setMode
        const { result, unmount } = renderHook(() => useTheme(), { wrapper });
        act(() => {
          result.current.setMode(mode);
        });
        expect(result.current.mode).toBe(mode);
        unmount();

        // Verify localStorage has the correct value
        expect(localStorageMock._getStore()[STORAGE_KEY]).toBe(mode);

        // Mount a fresh provider and verify it reads back the same mode
        const { result: freshResult, unmount: freshUnmount } = renderHook(
          () => useTheme(),
          { wrapper }
        );
        expect(freshResult.current.mode).toBe(mode);
        freshUnmount();
      }),
      { numRuns: 100 }
    );
  });

  it('for any invalid stored value, the system falls back to dark', () => {
    /**
     * **Validates: Requirements 1.8**
     *
     * For any arbitrary string that is NOT 'dark' or 'light' stored in
     * localStorage, the ThemeProvider falls back to 'dark' mode.
     */
    fc.assert(
      fc.property(invalidModeArb, (invalidValue) => {
        // Reset state
        localStorageMock.clear();
        document.documentElement.removeAttribute('data-theme');
        document.documentElement.classList.remove('dark', 'light');

        // Manually set an invalid value in localStorage
        localStorageMock.setItem(STORAGE_KEY, invalidValue);

        // Mount provider and verify it falls back to 'dark'
        const { result, unmount } = renderHook(() => useTheme(), { wrapper });
        expect(result.current.mode).toBe('dark');
        unmount();
      }),
      { numRuns: 100 }
    );
  });

  it('when localStorage throws, the system falls back to dark', () => {
    /**
     * **Validates: Requirements 1.8**
     *
     * When localStorage is unavailable (throws on access), the ThemeProvider
     * gracefully falls back to 'dark' mode without displaying an error.
     */
    fc.assert(
      fc.property(validModeArb, (mode) => {
        // Reset state
        localStorageMock.clear();
        document.documentElement.removeAttribute('data-theme');
        document.documentElement.classList.remove('dark', 'light');

        // Enable throw mode to simulate localStorage unavailability
        localStorageMock._setThrowMode(true);

        // Mount provider - should not throw and should default to 'dark'
        const { result, unmount } = renderHook(() => useTheme(), { wrapper });
        expect(result.current.mode).toBe('dark');
        unmount();

        // Restore localStorage
        localStorageMock._setThrowMode(false);
      }),
      { numRuns: 50 }
    );
  });

  it('the ThemeProvider correctly applies the persisted mode on mount', () => {
    /**
     * **Validates: Requirements 1.7**
     *
     * For any valid mode persisted in localStorage, when the ThemeProvider mounts,
     * it applies that mode to the document element (data-theme attribute and class).
     */
    fc.assert(
      fc.property(validModeArb, (mode) => {
        // Reset state
        localStorageMock.clear();
        document.documentElement.removeAttribute('data-theme');
        document.documentElement.classList.remove('dark', 'light');

        // Pre-set the mode in localStorage
        localStorageMock.setItem(STORAGE_KEY, mode);

        // Mount provider
        const { result, unmount } = renderHook(() => useTheme(), { wrapper });

        // Verify mode is applied to document
        expect(document.documentElement.getAttribute('data-theme')).toBe(mode);
        expect(document.documentElement.classList.contains(mode)).toBe(true);

        // Verify the opposite mode class is NOT present
        const oppositeMode = mode === 'dark' ? 'light' : 'dark';
        expect(document.documentElement.classList.contains(oppositeMode)).toBe(false);

        // Verify the hook returns the correct mode
        expect(result.current.mode).toBe(mode);
        unmount();
      }),
      { numRuns: 100 }
    );
  });
});

'use client';

import React, { forwardRef } from 'react';
import { useTheme } from '../providers/ThemeProvider';
import { neoBrutalism } from '../styles/tokens';

export type ButtonVariant = 'primary' | 'secondary' | 'outline';
export type ButtonSize = 'sm' | 'md' | 'lg';

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  /** Visual variant */
  variant?: ButtonVariant;
  /** Size preset */
  size?: ButtonSize;
  /** Full width button */
  fullWidth?: boolean;
  /** Loading state */
  loading?: boolean;
}

const sizeStyles: Record<ButtonSize, React.CSSProperties> = {
  sm: { padding: '8px 16px', fontSize: '14px' },
  md: { padding: '12px 24px', fontSize: '16px' },
  lg: { padding: '16px 32px', fontSize: '18px' },
};

/**
 * Button component with Neo Brutalism styling.
 *
 * - Primary: 0px border-radius, min 2px solid border, 4px hard shadow
 * - Secondary: subtle 4px border-radius, min 2px border, 4px hard shadow
 * - Outline: transparent background, min 2px border, 4px hard shadow
 *
 * Supports dark/light theme variants via useTheme hook.
 *
 * @see Requirements 1.1, 1.2
 */
export const Button = forwardRef<HTMLButtonElement, ButtonProps>(
  (
    {
      variant = 'primary',
      size = 'md',
      fullWidth = false,
      loading = false,
      disabled,
      style,
      children,
      ...props
    },
    ref
  ) => {
    const { mode, colors } = useTheme();
    const shadowColor = neoBrutalism.shadows.color[mode];

    const baseStyles: React.CSSProperties = {
      display: 'inline-flex',
      alignItems: 'center',
      justifyContent: 'center',
      gap: '8px',
      fontFamily: neoBrutalism.typography.body.family,
      fontWeight: 700,
      cursor: disabled || loading ? 'not-allowed' : 'pointer',
      transition: 'transform 0.1s ease, box-shadow 0.1s ease',
      opacity: disabled ? 0.6 : 1,
      width: fullWidth ? '100%' : undefined,
      ...sizeStyles[size],
    };

    const variantStyles: Record<ButtonVariant, React.CSSProperties> = {
      primary: {
        backgroundColor: colors.accentCyan,
        color: mode === 'dark' ? '#0A0A0A' : '#FFFFFF',
        border: `${neoBrutalism.borders.width.default} solid ${colors.border}`,
        borderRadius: neoBrutalism.borders.radius.none,
        boxShadow: `${neoBrutalism.shadows.offset.md} ${shadowColor}`,
      },
      secondary: {
        backgroundColor: colors.accentPurple,
        color: '#FFFFFF',
        border: `${neoBrutalism.borders.width.default} solid ${colors.border}`,
        borderRadius: neoBrutalism.borders.radius.subtle,
        boxShadow: `${neoBrutalism.shadows.offset.md} ${shadowColor}`,
      },
      outline: {
        backgroundColor: 'transparent',
        color: colors.textPrimary,
        border: `${neoBrutalism.borders.width.default} solid ${colors.border}`,
        borderRadius: neoBrutalism.borders.radius.none,
        boxShadow: `${neoBrutalism.shadows.offset.md} ${shadowColor}`,
      },
    };

    const combinedStyle: React.CSSProperties = {
      ...baseStyles,
      ...variantStyles[variant],
      ...style,
    };

    return (
      <button
        ref={ref}
        disabled={disabled || loading}
        style={combinedStyle}
        aria-busy={loading || undefined}
        {...props}
      >
        {loading && (
          <span
            aria-hidden="true"
            style={{
              width: '16px',
              height: '16px',
              border: '2px solid currentColor',
              borderTopColor: 'transparent',
              borderRadius: '50%',
              animation: 'spin 0.6s linear infinite',
            }}
          />
        )}
        {children}
      </button>
    );
  }
);

Button.displayName = 'Button';

'use client';

import React, { forwardRef } from 'react';
import { useTheme } from '../providers/ThemeProvider';
import { neoBrutalism } from '../styles/tokens';

export type CardVariant = 'default' | 'elevated' | 'flat';

export interface CardProps extends React.HTMLAttributes<HTMLDivElement> {
  /** Visual variant */
  variant?: CardVariant;
  /** Whether the card has hover effects */
  hoverable?: boolean;
  /** Custom padding */
  padding?: string;
}

/**
 * Card component with Neo Brutalism styling.
 *
 * - Thick borders (2-3px)
 * - Hard offset shadows (4-8px)
 * - 0px border-radius (sharp corners)
 * - Supports dark/light theme variants
 *
 * @see Requirements 1.1, 1.2
 */
export const Card = forwardRef<HTMLDivElement, CardProps>(
  (
    {
      variant = 'default',
      hoverable = false,
      padding = '24px',
      style,
      children,
      ...props
    },
    ref
  ) => {
    const { mode, colors } = useTheme();
    const shadowColor = neoBrutalism.shadows.color[mode];

    const variantStyles: Record<CardVariant, React.CSSProperties> = {
      default: {
        backgroundColor: colors.panel,
        border: `${neoBrutalism.borders.width.default} solid ${colors.border}`,
        borderRadius: neoBrutalism.borders.radius.none,
        boxShadow: `${neoBrutalism.shadows.offset.md} ${shadowColor}`,
      },
      elevated: {
        backgroundColor: colors.panel,
        border: `${neoBrutalism.borders.width.thick} solid ${colors.border}`,
        borderRadius: neoBrutalism.borders.radius.none,
        boxShadow: `${neoBrutalism.shadows.offset.xl} ${shadowColor}`,
      },
      flat: {
        backgroundColor: colors.panel,
        border: `${neoBrutalism.borders.width.default} solid ${colors.border}`,
        borderRadius: neoBrutalism.borders.radius.none,
        boxShadow: 'none',
      },
    };

    const combinedStyle: React.CSSProperties = {
      padding,
      transition: hoverable
        ? 'transform 0.2s ease, box-shadow 0.2s ease'
        : undefined,
      ...variantStyles[variant],
      ...style,
    };

    return (
      <div ref={ref} style={combinedStyle} {...props}>
        {children}
      </div>
    );
  }
);

Card.displayName = 'Card';

'use client';

import React, { forwardRef } from 'react';
import { useTheme } from '../providers/ThemeProvider';
import { neoBrutalism } from '../styles/tokens';

export type InputSize = 'sm' | 'md' | 'lg';

export interface InputProps
  extends Omit<React.InputHTMLAttributes<HTMLInputElement>, 'size'> {
  /** Size preset */
  size?: InputSize;
  /** Error state */
  error?: boolean;
  /** Error message to display */
  errorMessage?: string;
  /** Label text */
  label?: string;
  /** Full width input */
  fullWidth?: boolean;
}

const inputSizeStyles: Record<InputSize, React.CSSProperties> = {
  sm: { padding: '8px 12px', fontSize: '14px' },
  md: { padding: '12px 16px', fontSize: '16px' },
  lg: { padding: '16px 20px', fontSize: '18px' },
};

/**
 * Input component with Neo Brutalism form styling.
 *
 * - 2px solid border
 * - Sharp corners (0px border-radius)
 * - Focus state with accent color border
 * - Supports dark/light theme variants
 *
 * @see Requirements 1.1
 */
export const Input = forwardRef<HTMLInputElement, InputProps>(
  (
    {
      size = 'md',
      error = false,
      errorMessage,
      label,
      fullWidth = false,
      style,
      id,
      ...props
    },
    ref
  ) => {
    const { colors } = useTheme();
    const inputId = id || (label ? `input-${label.toLowerCase().replace(/\s+/g, '-')}` : undefined);

    const containerStyle: React.CSSProperties = {
      display: 'flex',
      flexDirection: 'column',
      gap: '4px',
      width: fullWidth ? '100%' : undefined,
    };

    const labelStyle: React.CSSProperties = {
      fontFamily: neoBrutalism.typography.body.family,
      fontSize: '14px',
      fontWeight: 600,
      color: colors.textPrimary,
    };

    const inputStyle: React.CSSProperties = {
      fontFamily: neoBrutalism.typography.body.family,
      backgroundColor: colors.background,
      color: colors.textPrimary,
      border: `${neoBrutalism.borders.width.default} solid ${error ? colors.accentCrimson : colors.border}`,
      borderRadius: neoBrutalism.borders.radius.none,
      outline: 'none',
      width: fullWidth ? '100%' : undefined,
      boxSizing: 'border-box',
      transition: 'border-color 0.15s ease',
