import {
  Controller,
  Post,
  Body,
  BadRequestException,
  UnauthorizedException,
  HttpCode,
  HttpStatus,
  UseGuards,
  Request,
  Get,
} from '@nestjs/common';
import { AuthGuard } from '@nestjs/passport';
import { AuthService as AuthLogicService } from './auth.service';
import { AuthServiceImpl } from './auth.service.impl';
import {
  RegisterDto,
  LoginDto,
  RefreshTokenDto,
  ChangePasswordDto,
  RequestPasswordResetDto,
  ResetPasswordDto,
  VerifyEmailDto,
  VerifyTotpDto,
  OAuthLoginDto,
} from './dto';

/**
 * Auth Controller
 *
 * Handles all authentication endpoints:
 * - Registration with email verification
 * - Login with JWT tokens
 * - Token refresh with rotation
 * - Password recovery and reset
 * - 2FA (TOTP) setup and verification
 * - OAuth login (Discord, Google)
 * - Password change with token invalidation
 */
@Controller('auth')
export class AuthController {
  constructor(private readonly authService: AuthServiceImpl) {}

  /**
   * POST /auth/register
   *
   * Register a new user account with email/password.
   * Sends verification email with 24-hour expiry token.
   *
   * Requirements: 9.1, 9.9
   */
  @Post('register')
  @HttpCode(HttpStatus.CREATED)
  async register(@Body() dto: RegisterDto) {
    try {
      const result = await this.authService.register(dto);
      return {
        userId: result.userId,
        message: 'Registration successful. Please verify your email.',
        verificationSent: result.verificationSent,
      };
    } catch (error) {
      if (error instanceof BadRequestException) {
        throw error;
      }
      const message = error instanceof Error ? error.message : 'Registration failed';
      throw new BadRequestException(message);
    }
  }

  /**
   * POST /auth/verify-email
   *
   * Verify email address using token from verification email.
   * Token expires after 24 hours.
   *
   * Requirements: 9.1
   */
  @Post('verify-email')
  @HttpCode(HttpStatus.OK)
  async verifyEmail(@Body() dto: VerifyEmailDto) {
    try {
      await this.authService.verifyEmail(dto.token);
      return { message: 'Email verified successfully' };
    } catch (error) {
      throw new BadRequestException('Invalid or expired verification token');
    }
  }

  /**
   * POST /auth/login
   *
   * Login with email and password.
   * Returns JWT access token (15min) and refresh token (7 days).
   * Implements account lock after 5 failed attempts (15min lock).
   *
   * Requirements: 9.2, 9.3, 9.5
   */
  @Post('login')
  @HttpCode(HttpStatus.OK)
  async login(@Body() dto: LoginDto) {
    try {
      const result = await this.authService.login(dto);
      return {
        accessToken: result.accessToken,
        refreshToken: result.refreshToken,
        expiresIn: result.expiresIn,
      };
    } catch (error) {
      if (error instanceof UnauthorizedException) {
        throw error;
      }
      const message = error instanceof Error ? error.message : 'Login failed';
      throw new UnauthorizedException(message);
    }
  }

  /**
   * POST /auth/refresh
   *
   * Refresh access token using refresh token.
   * Implements token rotation: old token is revoked, new pair issued.
   * New access token: 15 minutes
   * New refresh token: 7 days
   *
   * Requirements: 9.3
   */
  @Post('refresh')
  @HttpCode(HttpStatus.OK)
  async refreshToken(@Body() dto: RefreshTokenDto) {
    try {
      const result = await this.authService.refreshToken(dto.refreshToken);
      return {
        accessToken: result.accessToken,
        refreshToken: result.refreshToken,
        expiresIn: result.expiresIn,
      };
    } catch (error) {
      throw new UnauthorizedException('Invalid or expired refresh token');
    }
  }

  /**
   * POST /auth/request-password-reset
   *
   * Request password reset email.
   * Sends email with reset token valid for 30 minutes.
   *
   * Requirements: 9.8
   */
  @Post('request-password-reset')
  @HttpCode(HttpStatus.OK)
  async requestPasswordReset(@Body() dto: RequestPasswordResetDto) {
    try {
      await this.authService.requestPasswordReset(dto.email);
      return {
        message: 'Password reset email sent if account exists',
      };
    } catch (error) {
      // Don't reveal if email exists (security best practice)
      return {
        message: 'Password reset email sent if account exists',
      };
    }
  }

  /**
   * POST /auth/reset-password
   *
   * Reset password using token from reset email.
   * Token expires after 30 minutes.
   *
   * Requirements: 9.8
   */
  @Post('reset-password')
  @HttpCode(HttpStatus.OK)
  async resetPassword(@Body() dto: ResetPasswordDto) {
    try {
      await this.authService.resetPassword(dto.token, dto.newPassword);
      return { message: 'Password reset successfully' };
    } catch (error) {
      throw new BadRequestException('Invalid or expired reset token');
    }
  }

  /**
   * POST /auth/change-password
   *
   * Change password for authenticated user.
   * Invalidates all existing refresh tokens (security change).
   *
   * Requirements: 9.10
   */
  @Post('change-password')
  @UseGuards(AuthGuard('jwt'))
  @HttpCode(HttpStatus.OK)
  async changePassword(@Request() req: any, @Body() dto: ChangePasswordDto) {
    try {
      await this.authService.changePassword(req.user.id, dto);
      return { message: 'Password changed successfully' };
    } catch (error) {
      const message = error instanceof Error ? error.message : 'Password change failed';
      throw new BadRequestException(message);
    }
  }

  /**
   * POST /auth/enable-2fa
   *
   * Enable TOTP 2FA for authenticated user.
   * Returns secret and QR code for scanning.
   * Invalidates all existing refresh tokens (security change).
   *
   * Requirements: 9.4, 9.10
   */
  @Post('enable-2fa')
  @UseGuards(AuthGuard('jwt'))
  @HttpCode(HttpStatus.OK)
  async enableTwoFA(@Request() req: any) {
    try {
      const result = await this.authService.enableTwoFA(req.user.id);
      return {
        secret: result.secret,
        qrCode: result.qrCode,
        message: 'Scan QR code with authenticator app and verify with code',
      };
    } catch (error) {
      const message = error instanceof Error ? error.message : '2FA setup failed';
      throw new BadRequestException(message);
    }
  }

  /**
   * POST /auth/verify-2fa
   *
   * Verify TOTP code to complete 2FA setup.
   *
   * Requirements: 9.4
   */
  @Post('verify-2fa')
  @UseGuards(AuthGuard('jwt'))
  @HttpCode(HttpStatus.OK)
  async verifyTwoFA(@Request() req: any, @Body() dto: VerifyTotpDto) {
    try {
      await this.authService.verifyTwoFA(req.user.id, dto.code);
      return { message: '2FA enabled successfully' };
    } catch (error) {
      throw new BadRequestException('Invalid TOTP code');
    }
  }

  /**
   * POST /auth/oauth/login
   *
   * OAuth login via Discord or Google.
   * Returns JWT tokens if successful.
   *
   * Requirements: 9.2
   */
  @Post('oauth/login')
  @HttpCode(HttpStatus.OK)
  async oauthLogin(@Body() dto: OAuthLoginDto) {
    try {
      const result = await this.authService.oauthLogin(dto.provider, dto.code);
      return {
        accessToken: result.accessToken,
        refreshToken: result.refreshToken,
        expiresIn: result.expiresIn,
      };
    } catch (error) {
      throw new UnauthorizedException('OAuth login failed');
    }
  }

  /**
   * GET /auth/me
   *
   * Get current authenticated user profile.
   */
  @Get('me')
  @UseGuards(AuthGuard('jwt'))
  async getCurrentUser(@Request() req: any) {
    return req.user;
  }

  /**
   * POST /auth/logout
   *
   * Logout by invalidating refresh token.
   */
  @Post('logout')
  @UseGuards(AuthGuard('jwt'))
  @HttpCode(HttpStatus.OK)
  async logout(@Request() req: any) {
    try {
      await this.authService.logout(req.user.id);
      return { message: 'Logged out successfully' };
    } catch (error) {
      // Logout always succeeds from client perspective
      return { message: 'Logged out successfully' };
    }
  }
}

import { Injectable, BadRequestException, UnauthorizedException } from '@nestjs/common';
import { JwtService } from '@nestjs/jwt';
import { DatabaseService } from '../database/database.service';
import { AUTH } from '@perfect-world/shared';
import * as bcrypt from 'bcrypt';
import * as speakeasy from 'speakeasy';
import * as QRCode from 'qrcode';
import * as crypto from 'crypto';
import { AuthService as AuthLogicService } from './auth.service';
import {
  RegisterDto,
  LoginDto,
  ChangePasswordDto,
} from './dto';

/**
 * Auth Service Implementation
 *
 * Implements all authentication business logic:
 * - User registration with email verification
 * - Login with account locking
 * - Token refresh with rotation
 * - Password recovery and change
 * - TOTP 2FA setup and verification
 * - OAuth integration
 *
 * Uses AuthService for core logic (token refresh, account locking, etc.)
 */
@Injectable()
export class AuthServiceImpl {
  constructor(
    private readonly db: DatabaseService,
    private readonly jwtService: JwtService,
  ) {}

  /**
   * Register a new user account
   *
   * - Validates email/username uniqueness
   * - Hashes password with bcrypt
   * - Creates user with unverified email
   * - Generates and sends verification email
   *
   * Requirements: 9.1, 9.9
   */
  async register(dto: RegisterDto): Promise<{ userId: string; verificationSent: boolean }> {
    // Check if email already exists
    const existingEmail = await this.db.user.findUnique({
      where: { email: dto.email },
    });
    if (existingEmail) {
      throw new BadRequestException('Email already registered');
    }

    // Check if username already exists
    const existingUsername = await this.db.user.findUnique({
      where: { username: dto.username },
    });
    if (existingUsername) {
      throw new BadRequestException('Username already taken');
    }

    // Hash password
    const passwordHash = await bcrypt.hash(dto.password, 10);

    // Generate verification token (24-hour expiry)
    const verificationToken = this.generateRandomToken();
    const verificationExpiry = new Date(Date.now() + AUTH.EMAIL_VERIFICATION_EXPIRY_HOURS * 60 * 60 * 1000);

    // Create user
    const user = await this.db.user.create({
      data: {
        email: dto.email,
        username: dto.username,
        passwordHash,
        verificationToken,
        verificationExpiry,
        emailVerified: false,
      },
    });

    // TODO: Send verification email with verificationToken
    // For now, just return success
    const verificationSent = await this.sendVerificationEmail(user.email, verificationToken);

    return {
      userId: user.id,
      verificationSent,
    };
  }

  /**
   * Verify email address using token
   *
   * Requirements: 9.1
   */
  async verifyEmail(token: string): Promise<void> {
    const user = await this.db.user.findFirst({
      where: {
        verificationToken: token,
        verificationExpiry: {
          gt: new Date(),
        },
      },
    });

    if (!user) {
      throw new BadRequestException('Invalid or expired verification token');
    }

    await this.db.user.update({
      where: { id: user.id },
      data: {
        emailVerified: true,
        verificationToken: null,
        verificationExpiry: null,
      },
    });
  }

  /**
   * Login with email and password
   *
   * - Validates email exists and is verified
   * - Checks password
   * - Implements account locking after 5 failed attempts
   * - Returns JWT token pair
   *
   * Requirements: 9.2, 9.3, 9.5
   */
  async login(dto: LoginDto): Promise<{
    accessToken: string;
    refreshToken: string;
    expiresIn: number;
  }> {
    // Find user by email
    const user = await this.db.user.findUnique({
      where: { email: dto.email },
    });

    if (!user) {
      throw new UnauthorizedException('Invalid email or password');
    }

    // Check if email is verified
    if (!user.emailVerified) {
      throw new UnauthorizedException('Email not verified');
    }

    // Check if account is locked
    if (AuthLogicService.isAccountLocked(user)) {
      throw new UnauthorizedException(
        `Account locked. Try again in ${AUTH.ACCOUNT_LOCK_DURATION_MINUTES} minutes`,
      );
    }

    // Verify password
    const passwordCorrect = await bcrypt.compare(dto.password, user.passwordHash);

    // Process login attempt (handles failed attempts and locking)
    const { result, updatedUser } = AuthLogicService.processLoginAttempt(
      user,
      passwordCorrect,
    );

    // Update user state
    await this.db.user.update({
      where: { id: user.id },
      data: {
        failedLoginAttempts: updatedUser.failedLoginAttempts,
        lockedUntil: updatedUser.lockedUntil,
      },
    });

    if (!result.success) {
      throw new UnauthorizedException(
        result.locked
          ? `Account locked after ${result.failedAttempts} failed attempts`
          : 'Invalid email or password',
      );
    }

    // Check if 2FA is enabled
    if (user.totpEnabled && !dto.totpCode) {
      throw new UnauthorizedException('2FA code required');
    }

    if (user.totpEnabled && dto.totpCode) {
      const totpValid = speakeasy.totp.verify({
        secret: user.totpSecret!,
        encoding: 'base32',
        token: dto.totpCode,
        window: 2,
      });

      if (!totpValid) {
        throw new UnauthorizedException('Invalid 2FA code');
      }
    }

    // Generate token pair
    return this.generateTokenPair(user.id);
  }

  /**
   * Refresh access token using refresh token
   *
   * - Validates refresh token exists and is not expired
   * - Implements token rotation (old token deleted, new pair issued)
   * - New access token: 15 minutes
   * - New refresh token: 7 days
   *
   * Requirements: 9.3
   */
  async refreshToken(refreshToken: string): Promise<{
    accessToken: string;
    refreshToken: string;
    expiresIn: number;
  }> {
    // Verify JWT signature
    let decoded: any;
    try {
      decoded = this.jwtService.verify(refreshToken, {
        secret: process.env.JWT_REFRESH_SECRET || 'refresh-secret',
      });
    } catch (error) {
      throw new UnauthorizedException('Invalid refresh token');
    }

    // Find refresh token record
    const tokenRecord = await this.db.refreshToken.findUnique({
      where: { token: refreshToken },
    });

    if (!tokenRecord) {
      throw new UnauthorizedException('Token not found');
    }

    // Check if token is expired
    if (new Date() >= tokenRecord.expiresAt) {
      throw new UnauthorizedException('Token expired');
    }

    // Delete old token (rotation)
    await this.db.refreshToken.delete({
      where: { id: tokenRecord.id },
    });

    // Generate new token pair
    return this.generateTokenPair(decoded.sub);
  }

  /**
   * Request password reset email
   *
   * - Generates reset token valid for 30 minutes
   * - Sends email with reset link
   * - Does not reveal if email exists (security)
   *
   * Requirements: 9.8
   */
  async requestPasswordReset(email: string): Promise<void> {
    const user = await this.db.user.findUnique({
      where: { email },
    });

    if (!user) {
      // Don't reveal if email exists
      return;
    }

    // Generate reset token
    const resetToken = this.generateRandomToken();
    const resetExpiry = new Date(Date.now() + AUTH.PASSWORD_RESET_EXPIRY_MINUTES * 60 * 1000);

    // Store reset token
    await this.db.user.update({
      where: { id: user.id },
      data: {
        verificationToken: resetToken,
        verificationExpiry: resetExpiry,
      },
    });

    // TODO: Send password reset email
    await this.sendPasswordResetEmail(user.email, resetToken);
  }

  /**
   * Reset password using token
   *
   * Requirements: 9.8
   */
  async resetPassword(token: string, newPassword: string): Promise<void> {
    const user = await this.db.user.findFirst({
      where: {
        verificationToken: token,
        verificationExpiry: {
          gt: new Date(),
        },
      },
    });

    if (!user) {
      throw new BadRequestException('Invalid or expired reset token');
    }

    // Hash new password
    const passwordHash = await bcrypt.hash(newPassword, 10);

    // Update password and invalidate all refresh tokens
    await this.db.user.update({
      where: { id: user.id },
      data: {
        passwordHash,
        verificationToken: null,
        verificationExpiry: null,
      },
    });

    // Invalidate all refresh tokens (security change)
    await this.invalidateAllRefreshTokens(user.id);
  }

  /**
   * Change password for authenticated user
   *
   * - Validates old password
   * - Updates to new password
   * - Invalidates all refresh tokens (security change)
   *
   * Requirements: 9.10
   */
  async changePassword(userId: string, dto: ChangePasswordDto): Promise<void> {
    const user = await this.db.user.findUnique({
      where: { id: userId },
    });

    if (!user) {
      throw new BadRequestException('User not found');
    }

    // Verify old password
    const oldPasswordCorrect = await bcrypt.compare(dto.oldPassword, user.passwordHash);
    if (!oldPasswordCorrect) {
      throw new BadRequestException('Current password is incorrect');
    }

    // Hash new password
    const newPasswordHash = await bcrypt.hash(dto.newPassword, 10);

    // Update password
    await this.db.user.update({
      where: { id: userId },
      data: {
        passwordHash: newPasswordHash,
      },
    });

    // Invalidate all refresh tokens (security change)
    await this.invalidateAllRefreshTokens(userId);
  }

  /**
   * Enable TOTP 2FA for user
   *
   * - Generates TOTP secret
   * - Returns QR code for scanning
   * - Does not enable until verified
   * - Invalidates all refresh tokens (security change)
   *
   * Requirements: 9.4, 9.10
   */
  async enableTwoFA(userId: string): Promise<{ secret: string; qrCode: string }> {
    const user = await this.db.user.findUnique({
      where: { id: userId },
    });

    if (!user) {
      throw new BadRequestException('User not found');
    }

    // Generate TOTP secret
    const secret = speakeasy.generateSecret({
      name: `Perfect World (${user.email})`,
      issuer: 'Perfect World',
      length: 32,
    });

    // Generate QR code
    const qrCode = await QRCode.toDataURL(secret.otpauth_url!);

    // Store temporary secret (not enabled yet)
    await this.db.user.update({
      where: { id: userId },
      data: {
        totpSecret: secret.base32,
      },
    });

    return {
      secret: secret.base32,
      qrCode,
    };
  }

  /**
   * Verify TOTP code to complete 2FA setup
   *
   * Requirements: 9.4
   */
  async verifyTwoFA(userId: string, code: string): Promise<void> {
    const user = await this.db.user.findUnique({
      where: { id: userId },
    });

    if (!user || !user.totpSecret) {
      throw new BadRequestException('2FA setup not initiated');
    }

    // Verify TOTP code
    const totpValid = speakeasy.totp.verify({
      secret: user.totpSecret,
      encoding: 'base32',
      token: code,
      window: 2,
    });

    if (!totpValid) {
      throw new BadRequestException('Invalid TOTP code');
    }

    // Enable 2FA
    await this.db.user.update({
      where: { id: userId },
      data: {
        totpEnabled: true,
      },
    });

    // Invalidate all refresh tokens (security change)
    await this.invalidateAllRefreshTokens(userId);
  }

  /**
   * OAuth login via Discord or Google
   *
   * - Exchanges OAuth code for user info
   * - Creates or updates user
   * - Returns JWT token pair
   *
   * Requirements: 9.2
   */
  async oauthLogin(provider: 'discord' | 'google', code: string): Promise<{
    accessToken: string;
    refreshToken: string;
    expiresIn: number;
  }> {
    // TODO: Exchange code for user info from OAuth provider
    // For now, throw not implemented
    throw new BadRequestException('OAuth login not yet implemented');
  }

  /**
   * Logout by invalidating refresh token
   */
  async logout(userId: string): Promise<void> {
    // Invalidate all refresh tokens for user
    await this.invalidateAllRefreshTokens(userId);
  }

  /**
   * Generate JWT token pair
   *
   * - Access token: 15 minutes
   * - Refresh token: 7 days
   */
  private async generateTokenPair(userId: string): Promise<{
    accessToken: string;
    refreshToken: string;
    expiresIn: number;
  }> {
    const accessTokenExpirySeconds = AuthLogicService.computeAccessTokenExpirySeconds();
    const refreshTokenExpiry = AuthLogicService.computeRefreshTokenExpiry();

    // Generate access token
    const accessToken = this.jwtService.sign(
      { sub: userId },
      {
        secret: process.env.JWT_SECRET || 'secret',
        expiresIn: `${accessTokenExpirySeconds}s`,
      },
    );

    // Generate refresh token
    const refreshToken = this.jwtService.sign(
      { sub: userId },
      {
        secret: process.env.JWT_REFRESH_SECRET || 'refresh-secret',
        expiresIn: `${AUTH.REFRESH_TOKEN_EXPIRY_DAYS}d`,
      },
    );

    // Store refresh token in database
    await this.db.refreshToken.create({
      data: {
        token: refreshToken,
        userId,
        expiresAt: refreshTokenExpiry,
      },
    });

    return {
      accessToken,
      refreshToken,
      expiresIn: accessTokenExpirySeconds,
    };
  }

  /**
   * Invalidate all refresh tokens for a user
   *
   * Called on:
   * - Password change
   * - 2FA enable
   * - Logout
   */
  private async invalidateAllRefreshTokens(userId: string): Promise<void> {
    await this.db.refreshToken.deleteMany({
      where: {
        userId,
      },
    });
  }

  /**
   * Generate random token for email verification and password reset
   */
  private generateRandomToken(): string {
    return crypto.randomBytes(32).toString('hex');
  }

  /**
   * Send verification email
   *
   * TODO: Implement email sending
   */
  private async sendVerificationEmail(email: string, token: string): Promise<boolean> {
