import React, { forwardRef } from 'react';
import { useTheme } from '../providers/ThemeProvider';
import { neoBrutalism } from '../styles/tokens';

export interface TableColumn<T = Record<string, unknown>> {
  /** Column header text */
  header: string;
  /** Key to access data from row object */
  accessor: keyof T | string;
  /** Custom cell renderer */
  render?: (value: unknown, row: T, index: number) => React.ReactNode;
  /** Column width */
  width?: string;
  /** Text alignment */
  align?: 'left' | 'center' | 'right';
}

export interface TableProps<T = Record<string, unknown>>
  extends Omit<React.HTMLAttributes<HTMLTableElement>, 'children'> {
  /** Column definitions */
  columns: TableColumn<T>[];
  /** Row data */
  data: T[];
  /** Whether to show alternating row backgrounds */
  striped?: boolean;
  /** Whether to show hover effect on rows */
  hoverable?: boolean;
  /** Custom row key extractor */
  rowKey?: (row: T, index: number) => string;
}

/**
 * Table component with Neo Brutalism styling.
 *
 * - 2px row borders
 * - Alternating panel/background colors
 * - Bold header text
 * - Supports dark/light theme variants
 *
 * @see Requirements 6.5
 */
export const Table = forwardRef<HTMLTableElement, TableProps>(
  (
    {
      columns,
      data,
      striped = true,
      hoverable = false,
      rowKey,
      style,
      ...props
    },
    ref
  ) => {
    const { mode, colors } = useTheme();
    const shadowColor = neoBrutalism.shadows.color[mode];

    const tableContainerStyle: React.CSSProperties = {
      width: '100%',
      overflowX: 'auto',
      border: `${neoBrutalism.borders.width.default} solid ${colors.border}`,
      boxShadow: `${neoBrutalism.shadows.offset.md} ${shadowColor}`,
    };

    const tableStyle: React.CSSProperties = {
      width: '100%',
      borderCollapse: 'collapse',
      fontFamily: neoBrutalism.typography.body.family,
      fontSize: neoBrutalism.typography.body.size,
      color: colors.textPrimary,
      ...style,
    };

    const thStyle: React.CSSProperties = {
      padding: '12px 16px',
      fontWeight: 700,
      textAlign: 'left',
      backgroundColor: colors.panel,
      borderBottom: `${neoBrutalism.borders.width.default} solid ${colors.border}`,
      whiteSpace: 'nowrap',
    };

    const getRowStyle = (index: number): React.CSSProperties => ({
      backgroundColor: striped
        ? index % 2 === 0
          ? colors.background
          : colors.panel
        : colors.background,
      borderBottom: `${neoBrutalism.borders.width.default} solid ${colors.border}`,
      transition: hoverable ? 'background-color 0.15s ease' : undefined,
    });

    const tdStyle: React.CSSProperties = {
      padding: '12px 16px',
    };

    const getKey = (row: Record<string, unknown>, index: number): string => {
      if (rowKey) return rowKey(row as never, index);
      return String((row as Record<string, unknown>)['id'] ?? index);
    };

    const getCellValue = (row: Record<string, unknown>, accessor: string): unknown => {
      return (row as Record<string, unknown>)[accessor];
    };

    return (
      <div style={tableContainerStyle}>
        <table ref={ref} style={tableStyle} {...props}>
          <thead>
            <tr>
              {columns.map((col) => (
                <th
                  key={String(col.accessor)}
                  style={{
                    ...thStyle,
                    width: col.width,
                    textAlign: col.align || 'left',
                  }}
                >
                  {col.header}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {data.map((row, rowIndex) => (
              <tr key={getKey(row as Record<string, unknown>, rowIndex)} style={getRowStyle(rowIndex)}>
                {columns.map((col) => {
                  const value = getCellValue(row as Record<string, unknown>, String(col.accessor));
                  return (
                    <td
                      key={String(col.accessor)}
                      style={{ ...tdStyle, textAlign: col.align || 'left' }}
                    >
                      {col.render
                        ? col.render(value, row as never, rowIndex)
                        : String(value ?? '')}
                    </td>
                  );
                })}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    );
  }
) as <T = Record<string, unknown>>(
  props: TableProps<T> & { ref?: React.Ref<HTMLTableElement> }
) => React.ReactElement;

(Table as { displayName?: string }).displayName = 'Table';

