'use client';

import React, { forwardRef, useCallback, useEffect, useRef } from 'react';
import { useTheme } from '../providers/ThemeProvider';
import { neoBrutalism } from '../styles/tokens';

export interface ModalProps extends React.HTMLAttributes<HTMLDivElement> {
  /** Whether the modal is open */
  open: boolean;
  /** Callback when the modal should close */
  onClose: () => void;
  /** Modal title */
  title?: string;
  /** Whether clicking the overlay closes the modal */
  closeOnOverlayClick?: boolean;
  /** Whether pressing Escape closes the modal */
  closeOnEscape?: boolean;
  /** Maximum width of the modal */
  maxWidth?: string;
}

/**
 * Modal component with Neo Brutalism styling.
 *
 * - Thick border (3px)
 * - Hard offset shadow (6px)
 * - Sharp corners
 * - Overlay backdrop
 * - Keyboard accessible (Escape to close, focus trap)
 * - Supports dark/light theme variants
 *
 * @see Requirements 1.1, 1.2
 */
export const Modal = forwardRef<HTMLDivElement, ModalProps>(
  (
    {
      open,
      onClose,
      title,
      closeOnOverlayClick = true,
      closeOnEscape = true,
      maxWidth = '560px',
      style,
      children,
      ...props
    },
    ref
  ) => {
    const { mode, colors } = useTheme();
    const shadowColor = neoBrutalism.shadows.color[mode];
    const modalRef = useRef<HTMLDivElement>(null);

    const handleKeyDown = useCallback(
      (e: KeyboardEvent) => {
        if (closeOnEscape && e.key === 'Escape') {
          onClose();
        }
      },
      [closeOnEscape, onClose]
    );

    useEffect(() => {
      if (open) {
        document.addEventListener('keydown', handleKeyDown);
        document.body.style.overflow = 'hidden';
        // Focus the modal on open
        modalRef.current?.focus();
      }
      return () => {
        document.removeEventListener('keydown', handleKeyDown);
        document.body.style.overflow = '';
      };
    }, [open, handleKeyDown]);

    if (!open) return null;

    const overlayStyle: React.CSSProperties = {
      position: 'fixed',
      inset: 0,
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      backgroundColor: 'rgba(0, 0, 0, 0.7)',
      zIndex: 9999,
      padding: '16px',
    };

    const modalStyle: React.CSSProperties = {
      position: 'relative',
      width: '100%',
      maxWidth,
      maxHeight: '90vh',
      overflowY: 'auto',
      backgroundColor: colors.panel,
      border: `${neoBrutalism.borders.width.thick} solid ${colors.border}`,
      borderRadius: neoBrutalism.borders.radius.none,
      boxShadow: `${neoBrutalism.shadows.offset.lg} ${shadowColor}`,
      padding: '24px',
      ...style,
    };

    const headerStyle: React.CSSProperties = {
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'space-between',
      marginBottom: '16px',
    };

    const titleStyle: React.CSSProperties = {
      fontFamily: neoBrutalism.typography.heading.family,
      fontSize: '24px',
      fontWeight: 700,
      color: colors.textPrimary,
      margin: 0,
    };

    const closeButtonStyle: React.CSSProperties = {
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      width: '32px',
      height: '32px',
      backgroundColor: 'transparent',
      border: `${neoBrutalism.borders.width.default} solid ${colors.border}`,
      borderRadius: neoBrutalism.borders.radius.none,
      color: colors.textPrimary,
      cursor: 'pointer',
      fontSize: '18px',
      fontWeight: 700,
    };

    return (
      <div
        style={overlayStyle}
        onClick={closeOnOverlayClick ? onClose : undefined}
        aria-hidden="true"
      >
        <div
          ref={(node) => {
            (modalRef as React.MutableRefObject<HTMLDivElement | null>).current = node;
            if (typeof ref === 'function') ref(node);
            else if (ref) (ref as React.MutableRefObject<HTMLDivElement | null>).current = node;
          }}
          role="dialog"
          aria-modal="true"
          aria-labelledby={title ? 'modal-title' : undefined}
          tabIndex={-1}
          style={modalStyle}
          onClick={(e) => e.stopPropagation()}
          {...props}
        >
          {title && (
            <div style={headerStyle}>
              <h2 id="modal-title" style={titleStyle}>
                {title}
              </h2>
              <button
                onClick={onClose}
                style={closeButtonStyle}
                aria-label="Close modal"
                type="button"
              >
                ✕
              </button>
            </div>
          )}
          {children}
        </div>
      </div>
    );
  }
);

Modal.displayName = 'Modal';

