}

/**
 * Skeleton loading placeholder with Neo Brutalism styling.
 *
 * - 2px solid border
 * - Sharp corners for rectangular/text
 * - Pulse animation for loading state
 * - Supports dark/light theme variants
 *
 * @see Requirements 3.7
 */
export const Skeleton = forwardRef<HTMLDivElement, SkeletonProps>(
  (
    {
      variant = 'rectangular',
      width,
      height,
      lines = 1,
      animate = true,
      style,
      ...props
    },
    ref
  ) => {
    const { colors } = useTheme();

    const baseStyle: React.CSSProperties = {
      backgroundColor: colors.border,
      border: `${neoBrutalism.borders.width.default} solid ${colors.border}`,
      opacity: 0.3,
      animation: animate ? 'pulse 1.5s ease-in-out infinite' : undefined,
    };

    const variantStyles: Record<SkeletonVariant, React.CSSProperties> = {
      text: {
        borderRadius: neoBrutalism.borders.radius.none,
        height: height || '16px',
        width: width || '100%',
      },
      rectangular: {
        borderRadius: neoBrutalism.borders.radius.none,
        width: width || '100%',
        height: height || '100px',
      },
      circular: {
        borderRadius: '50%',
        width: width || '48px',
        height: height || '48px',
      },
    };

    if (variant === 'text' && lines > 1) {
      return (
        <div
          ref={ref}
          style={{ display: 'flex', flexDirection: 'column', gap: '8px', ...style }}
          aria-busy="true"
          aria-label="Loading content"
          {...props}
        >
          {Array.from({ length: lines }).map((_, i) => (
            <div
              key={i}
              style={{
                ...baseStyle,
                ...variantStyles.text,
                width: i === lines - 1 ? '70%' : '100%',
              }}
            />
          ))}
        </div>
      );
    }

    return (
      <div
        ref={ref}
        aria-busy="true"
        aria-label="Loading content"
        style={{
          ...baseStyle,
          ...variantStyles[variant],
          ...style,
        }}
        {...props}
      />
    );
  }
);

