'use client';

import React, {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useState,
} from 'react';
import { neoBrutalism } from '../styles/tokens';
import type { ThemeContextValue, ThemeMode } from '../types';

const STORAGE_KEY = 'pw-theme-mode';
const VALID_MODES: ThemeMode[] = ['dark', 'light'];
const DEFAULT_MODE: ThemeMode = 'dark';

/**
 * Reads the persisted theme mode from localStorage.
 * Returns the default ('dark') if localStorage is unavailable or the value is invalid.
 */
function getPersistedMode(): ThemeMode {
  try {
    const stored = localStorage.getItem(STORAGE_KEY);
    if (stored && VALID_MODES.includes(stored as ThemeMode)) {
      return stored as ThemeMode;
    }
  } catch {
    // localStorage unavailable (SSR, private browsing, etc.)
  }
  return DEFAULT_MODE;
}

/**
 * Persists the theme mode to localStorage.
 * Silently fails if localStorage is unavailable.
 */
function persistMode(mode: ThemeMode): void {
  try {
    localStorage.setItem(STORAGE_KEY, mode);
  } catch {
    // Silently ignore write failures
  }
}

const ThemeContext = createContext<ThemeContextValue | null>(null);

export interface ThemeProviderProps {
  /** Optional initial mode override (useful for SSR or testing) */
  defaultMode?: ThemeMode;
  children: React.ReactNode;
}

/**
 * ThemeProvider
 *
 * Provides dark/light mode switching with localStorage persistence.
 * Falls back to dark mode if localStorage is unavailable or the stored value is invalid.
 *
 * For flicker-free theme application within 50ms of page render start,
 * include the ThemeInitScript in your document <head>.
 *
 * @see Requirements 1.5, 1.6, 1.7, 1.8
 */
export function ThemeProvider({ defaultMode, children }: ThemeProviderProps) {
  const [mode, setModeState] = useState<ThemeMode>(
    () => defaultMode ?? getPersistedMode()
  );

  const setMode = useCallback((newMode: ThemeMode) => {
    if (!VALID_MODES.includes(newMode)) return;
    setModeState(newMode);
    persistMode(newMode);
    applyModeToDocument(newMode);
  }, []);

  const toggleMode = useCallback(() => {
    setModeState((prev) => {
      const next: ThemeMode = prev === 'dark' ? 'light' : 'dark';
      persistMode(next);
      applyModeToDocument(next);
      return next;
    });
  }, []);

  const colors = useMemo(() => neoBrutalism.colors[mode], [mode]);

  // Apply mode to document on mount (client-side hydration)
  useEffect(() => {
    applyModeToDocument(mode);
  }, [mode]);

  const value: ThemeContextValue = useMemo(
    () => ({ mode, setMode, toggleMode, colors }),
    [mode, setMode, toggleMode, colors]
  );

  return (
    <ThemeContext.Provider value={value}>{children}</ThemeContext.Provider>
  );
}

/**
 * useTheme hook
 *
 * Returns the current theme context including mode, setMode, toggleMode, and colors.
 * Must be used within a ThemeProvider.
 */
export function useTheme(): ThemeContextValue {
  const context = useContext(ThemeContext);
  if (!context) {
    throw new Error('useTheme must be used within a ThemeProvider');
  }
  return context;
}

/**
 * Applies the theme mode to the document element as a data attribute.
 * This enables CSS selectors like [data-theme="dark"] for styling.
 */
function applyModeToDocument(mode: ThemeMode): void {
  if (typeof document !== 'undefined') {
    document.documentElement.setAttribute('data-theme', mode);
    document.documentElement.classList.remove('dark', 'light');
    document.documentElement.classList.add(mode);
  }
}

/**
 * Blocking script content for <head> injection.
 *
 * This script runs synchronously before first paint to read the persisted theme
 * from localStorage and apply it to the document element, preventing flash of
 * wrong theme (FOWT). Ensures theme is applied within 50ms of page render start.
 *
 * Usage in Next.js layout:
 * ```tsx
 * <head>
 *   <script dangerouslySetInnerHTML={{ __html: themeInitScript }} />
 * </head>
 * ```
 *
 * @see Requirement 1.7
 */
export const themeInitScript = `(function(){try{var t=localStorage.getItem('${STORAGE_KEY}');if(t!=='dark'&&t!=='light')t='light';document.documentElement.setAttribute('data-theme',t);document.documentElement.classList.add(t)}catch(e){document.documentElement.setAttribute('data-theme','light');document.documentElement.classList.add('light')}})();`;

