import { describe, it, expect } from 'vitest';
import fc from 'fast-check';
import {
  getRateLimit,
  getTrackerKey,
  shouldAllowRequest,
  simulateRateLimiting,
  RATE_LIMIT,
} from './rate-limit.logic';

/**
 * Property-Based Tests for Rate Limiting
 *
 * **Validates: Requirements 9.7**
 *
 * Property 23: Rate Limiting
 * For any authenticated user making N requests within a 60-second window,
 * requests SHALL be allowed when N <= 100 and rejected when N > 100.
 * For any unauthenticated IP making N requests within a 60-second window,
 * requests SHALL be allowed when N <= 30 and rejected when N > 30.
 */

// ─── Generators ───────────────────────────────────────────────────────

/** Generate a valid user ID (UUID-like string) */
const userIdArb = fc.uuid();

/** Generate a valid IP address */
const ipAddressArb = fc.tuple(
  fc.integer({ min: 1, max: 255 }),
  fc.integer({ min: 0, max: 255 }),
  fc.integer({ min: 0, max: 255 }),
  fc.integer({ min: 1, max: 254 }),
).map(([a, b, c, d]) => `${a}.${b}.${c}.${d}`);

/** Generate an authenticated user object */
const authenticatedUserArb = userIdArb.map((id) => ({ sub: id }));

/** Generate request count within authenticated limit */
const withinAuthLimitArb = fc.integer({ min: 1, max: RATE_LIMIT.AUTHENTICATED_LIMIT });

/** Generate request count exceeding authenticated limit */
const exceedingAuthLimitArb = fc.integer({
  min: RATE_LIMIT.AUTHENTICATED_LIMIT + 1,
  max: RATE_LIMIT.AUTHENTICATED_LIMIT * 10,
});

/** Generate request count within unauthenticated limit */
const withinUnauthLimitArb = fc.integer({ min: 1, max: RATE_LIMIT.UNAUTHENTICATED_LIMIT });

/** Generate request count exceeding unauthenticated limit */
const exceedingUnauthLimitArb = fc.integer({
  min: RATE_LIMIT.UNAUTHENTICATED_LIMIT + 1,
  max: RATE_LIMIT.UNAUTHENTICATED_LIMIT * 10,
});

// ─── Property Tests: Authenticated Rate Limiting ──────────────────────

describe('Feature: perfect-world-neo-brutalism, Property 23: Rate Limiting', () => {
  describe('Authenticated users are limited to 100 requests/minute', () => {
    it('allows all requests when count is within the 100 request limit', () => {
      fc.assert(
        fc.property(withinAuthLimitArb, (requestCount) => {
          const allowed = shouldAllowRequest(requestCount, true);
          expect(allowed).toBe(true);
        }),
        { numRuns: 200 }
      );
    });

    it('rejects requests when count exceeds the 100 request limit', () => {
      fc.assert(
        fc.property(exceedingAuthLimitArb, (requestCount) => {
          const allowed = shouldAllowRequest(requestCount, false);
          // Even if we pass false (unauthenticated), exceeding 30 should reject
          // But for authenticated exceeding 100:
          const allowedAuth = shouldAllowRequest(requestCount, true);
          expect(allowedAuth).toBe(false);
        }),
        { numRuns: 200 }
      );
    });

    it('returns limit of 100 for any authenticated user', () => {
      fc.assert(
        fc.property(authenticatedUserArb, (user) => {
          const limit = getRateLimit(user);
          expect(limit).toBe(100);
        }),
        { numRuns: 200 }
      );
    });

    it('simulation allows exactly 100 requests then rejects for authenticated users', () => {
      fc.assert(
        fc.property(
          fc.integer({ min: 101, max: 500 }),
          (totalRequests) => {
            const results = simulateRateLimiting(totalRequests, true);

            // First 100 should be allowed
            const allowedCount = results.filter((r) => r).length;
            expect(allowedCount).toBe(100);

            // Requests 101+ should be rejected
            const rejectedCount = results.filter((r) => !r).length;
            expect(rejectedCount).toBe(totalRequests - 100);

            // Verify boundary: request 100 is allowed, request 101 is rejected
            expect(results[99]).toBe(true);
            expect(results[100]).toBe(false);
          }
        ),
        { numRuns: 100 }
      );
    });
  });

  // ─── Property Tests: Unauthenticated Rate Limiting ────────────────────

  describe('Unauthenticated users are limited to 30 requests/minute', () => {
    it('allows all requests when count is within the 30 request limit', () => {
      fc.assert(
        fc.property(withinUnauthLimitArb, (requestCount) => {
          const allowed = shouldAllowRequest(requestCount, false);
          expect(allowed).toBe(true);
        }),
        { numRuns: 200 }
      );
    });

    it('rejects requests when count exceeds the 30 request limit', () => {
      fc.assert(
        fc.property(exceedingUnauthLimitArb, (requestCount) => {
          const allowed = shouldAllowRequest(requestCount, false);
          expect(allowed).toBe(false);
        }),
        { numRuns: 200 }
      );
    });

    it('returns limit of 30 for unauthenticated users (no user object)', () => {
      fc.assert(
        fc.property(fc.constant(undefined), (_) => {
          const limit = getRateLimit(undefined);
          expect(limit).toBe(30);
        }),
        { numRuns: 10 }
      );
    });

    it('returns limit of 30 for users without sub field', () => {
      const noSubUser = fc.record({
        email: fc.emailAddress(),
      });

      fc.assert(
        fc.property(noSubUser, (user) => {
          const limit = getRateLimit(user as any);
          expect(limit).toBe(30);
        }),
        { numRuns: 100 }
      );
    });

    it('simulation allows exactly 30 requests then rejects for unauthenticated users', () => {
      fc.assert(
        fc.property(
          fc.integer({ min: 31, max: 200 }),
          (totalRequests) => {
            const results = simulateRateLimiting(totalRequests, false);

            // First 30 should be allowed
            const allowedCount = results.filter((r) => r).length;
            expect(allowedCount).toBe(30);

            // Requests 31+ should be rejected
            const rejectedCount = results.filter((r) => !r).length;
            expect(rejectedCount).toBe(totalRequests - 30);

            // Verify boundary: request 30 is allowed, request 31 is rejected
            expect(results[29]).toBe(true);
            expect(results[30]).toBe(false);
          }
        ),
        { numRuns: 100 }
      );
    });
  });

  // ─── Property Tests: Rejection with Appropriate Error ─────────────────

  describe('Requests beyond the limit are rejected with appropriate error responses', () => {
    it('for any N > limit, shouldAllowRequest returns false (authenticated)', () => {
      fc.assert(
        fc.property(
          fc.integer({ min: RATE_LIMIT.AUTHENTICATED_LIMIT + 1, max: 10000 }),
          (requestCount) => {
            expect(shouldAllowRequest(requestCount, true)).toBe(false);
          }
        ),
        { numRuns: 200 }
      );
    });

    it('for any N > limit, shouldAllowRequest returns false (unauthenticated)', () => {
      fc.assert(
        fc.property(
          fc.integer({ min: RATE_LIMIT.UNAUTHENTICATED_LIMIT + 1, max: 10000 }),
          (requestCount) => {
            expect(shouldAllowRequest(requestCount, false)).toBe(false);
          }
        ),
        { numRuns: 200 }
      );
    });

    it('the boundary is exact: N=limit is allowed, N=limit+1 is rejected', () => {
      // Authenticated boundary
      expect(shouldAllowRequest(RATE_LIMIT.AUTHENTICATED_LIMIT, true)).toBe(true);
      expect(shouldAllowRequest(RATE_LIMIT.AUTHENTICATED_LIMIT + 1, true)).toBe(false);

      // Unauthenticated boundary
      expect(shouldAllowRequest(RATE_LIMIT.UNAUTHENTICATED_LIMIT, false)).toBe(true);
      expect(shouldAllowRequest(RATE_LIMIT.UNAUTHENTICATED_LIMIT + 1, false)).toBe(false);
    });
  });

  // ─── Property Tests: Rate Limit Resets After Time Window ──────────────

  describe('Rate limit resets after the time window', () => {
    it('the time window is configured as 60 seconds (60000ms)', () => {
      expect(RATE_LIMIT.WINDOW_MS).toBe(60000);
    });

    it('after a simulated reset, all requests within limit are allowed again', () => {
      fc.assert(
        fc.property(
          fc.integer({ min: 1, max: 5 }), // number of windows to simulate
          fc.boolean(), // authenticated or not
          (windowCount, isAuthenticated) => {
            const limit = isAuthenticated
              ? RATE_LIMIT.AUTHENTICATED_LIMIT
              : RATE_LIMIT.UNAUTHENTICATED_LIMIT;

            // Simulate multiple time windows
            for (let window = 0; window < windowCount; window++) {
              // Each window starts fresh - all requests up to limit should be allowed
              const results = simulateRateLimiting(limit + 10, isAuthenticated);

              // First `limit` requests are allowed
              for (let i = 0; i < limit; i++) {
                expect(results[i]).toBe(true);
              }

              // Requests beyond limit are rejected
              for (let i = limit; i < results.length; i++) {
                expect(results[i]).toBe(false);
              }
            }
          }
        ),
        { numRuns: 50 }
      );
    });

    it('rate limit counter resets independently per window regardless of previous usage', () => {
      fc.assert(
        fc.property(
          fc.boolean(), // authenticated or not
          fc.integer({ min: 1, max: 200 }), // requests in first window
          fc.integer({ min: 1, max: 200 }), // requests in second window (after reset)
          (isAuthenticated, firstWindowRequests, secondWindowRequests) => {
            const limit = isAuthenticated
              ? RATE_LIMIT.AUTHENTICATED_LIMIT
              : RATE_LIMIT.UNAUTHENTICATED_LIMIT;

            // First window
            const firstResults = simulateRateLimiting(firstWindowRequests, isAuthenticated);
            const firstAllowed = firstResults.filter((r) => r).length;
            expect(firstAllowed).toBe(Math.min(firstWindowRequests, limit));

            // After reset (new window), the counter starts fresh
            const secondResults = simulateRateLimiting(secondWindowRequests, isAuthenticated);
            const secondAllowed = secondResults.filter((r) => r).length;
            expect(secondAllowed).toBe(Math.min(secondWindowRequests, limit));
          }
        ),
        { numRuns: 100 }
      );
    });
  });

  // ─── Property Tests: Tracker Key Differentiation ──────────────────────

  describe('Tracker key differentiation', () => {
    it('different authenticated users get different tracker keys', () => {
      fc.assert(
        fc.property(
          userIdArb,
          userIdArb.filter((id) => id !== ''),
          (userId1, userId2) => {
            fc.pre(userId1 !== userId2);

            const key1 = getTrackerKey({ user: { sub: userId1 }, ip: '10.0.0.1' });
            const key2 = getTrackerKey({ user: { sub: userId2 }, ip: '10.0.0.1' });

            expect(key1).not.toBe(key2);
          }
        ),
        { numRuns: 200 }
      );
    });

    it('same authenticated user always gets the same tracker key regardless of IP', () => {
      fc.assert(
        fc.property(
          userIdArb,
          ipAddressArb,
          ipAddressArb,
          (userId, ip1, ip2) => {
            const key1 = getTrackerKey({ user: { sub: userId }, ip: ip1 });
            const key2 = getTrackerKey({ user: { sub: userId }, ip: ip2 });

            expect(key1).toBe(key2);
          }
        ),
        { numRuns: 200 }
      );
    });

    it('different unauthenticated IPs get different tracker keys', () => {
      fc.assert(
        fc.property(
          ipAddressArb,
          ipAddressArb,
          (ip1, ip2) => {
            fc.pre(ip1 !== ip2);

            const key1 = getTrackerKey({ ip: ip1 });
            const key2 = getTrackerKey({ ip: ip2 });

            expect(key1).not.toBe(key2);
          }
        ),
        { numRuns: 200 }
      );
    });

    it('authenticated tracker keys are prefixed and distinct from IP-based keys', () => {
      fc.assert(
        fc.property(
          userIdArb,
          ipAddressArb,
          (userId, ip) => {
            const authKey = getTrackerKey({ user: { sub: userId }, ip });
            const unauthKey = getTrackerKey({ ip });

            // Auth key should be prefixed
            expect(authKey.startsWith('authenticated_')).toBe(true);
            // They should never collide
            expect(authKey).not.toBe(unauthKey);
          }
        ),
        { numRuns: 200 }
      );
    });
  });
});

/**
 * Rate limiting logic extracted for testability.
 *
 * Rate limits:
 * - Authenticated users: 100 requests per minute (keyed by user ID)
 * - Unauthenticated users: 30 requests per minute (keyed by IP address)
 *
 * Time window: 60 seconds (60000ms)
 */

export const RATE_LIMIT = {
  AUTHENTICATED_LIMIT: 100,
  UNAUTHENTICATED_LIMIT: 30,
  WINDOW_MS: 60000,
} as const;

/**
 * Determines the rate limit for a request based on authentication status.
 * Authenticated users (those with a valid user.sub) get 100 req/min.
 * Unauthenticated users get 30 req/min.
 */
export function getRateLimit(user: { sub?: string } | undefined | null): number {
  if (user && user.sub) {
    return RATE_LIMIT.AUTHENTICATED_LIMIT;
  }
  return RATE_LIMIT.UNAUTHENTICATED_LIMIT;
}

/**
 * Generates a unique tracking key for rate limiting.
 * Authenticated users are tracked by their user ID.
 * Unauthenticated users are tracked by their IP address.
 */
export function getTrackerKey(req: {
  user?: { sub?: string } | null;
  ip?: string;
  connection?: { remoteAddress?: string };
}): string {
  const user = req.user;
  if (user && user.sub) {
    return `authenticated_${user.sub}`;
  }
  return req.ip || req.connection?.remoteAddress || 'unknown';
}

/**
 * Determines whether a request should be allowed based on the current
 * request count within the time window.
 *
 * @param requestCount - Number of requests made in the current window
 * @param isAuthenticated - Whether the requester is authenticated
 * @returns true if the request should be allowed, false if it should be rejected
 */
export function shouldAllowRequest(requestCount: number, isAuthenticated: boolean): boolean {
  const limit = isAuthenticated ? RATE_LIMIT.AUTHENTICATED_LIMIT : RATE_LIMIT.UNAUTHENTICATED_LIMIT;
  return requestCount <= limit;
}

/**
 * Simulates rate limiting over a series of requests within a time window.
 * Returns an array of booleans indicating whether each request was allowed.
 *
 * @param totalRequests - Total number of requests to simulate
 * @param isAuthenticated - Whether the requester is authenticated
 * @returns Array of booleans (true = allowed, false = rejected)
 */
export function simulateRateLimiting(totalRequests: number, isAuthenticated: boolean): boolean[] {
  const limit = isAuthenticated ? RATE_LIMIT.AUTHENTICATED_LIMIT : RATE_LIMIT.UNAUTHENTICATED_LIMIT;
  const results: boolean[] = [];

  for (let i = 1; i <= totalRequests; i++) {
    results.push(i <= limit);
  }

  return results;
}

import { describe, it, expect } from 'vitest';
import fc from 'fast-check';
import { AUTH } from '@perfect-world/shared';
import {
  AuthService,
  RefreshTokenRecord,
  UserAuthState,
} from './auth.service';

/**
 * Property-Based Tests for Auth Service
 *
 * Validates: Requirements 9.3, 9.5, 9.10
 */

// ─── Helpers / Arbitraries ────────────────────────────────────────────

/** Generate a valid user ID */
const userIdArb = fc.uuid();

/** Generate a Date within a reasonable range (using integer timestamps to avoid NaN) */
const dateArb = fc.integer({
  min: new Date('2024-01-01').getTime(),
  max: new Date('2030-12-31').getTime(),
}).map((ts) => new Date(ts));

/** Generate a UserAuthState with configurable failed attempts */
function userAuthStateArb(opts?: {
  failedAttempts?: fc.Arbitrary<number>;
  lockedUntil?: fc.Arbitrary<Date | null>;
}): fc.Arbitrary<UserAuthState> {
  return fc.record({
    id: userIdArb,
    email: fc.emailAddress(),
    passwordHash: fc.string({ minLength: 60, maxLength: 60 }),
    failedLoginAttempts: opts?.failedAttempts ?? fc.integer({ min: 0, max: 10 }),
    lockedUntil: opts?.lockedUntil ?? fc.constant(null),
    totpEnabled: fc.boolean(),
  });
}

/** Generate a valid (non-revoked, non-expired) refresh token record */
function validRefreshTokenArb(now: Date): fc.Arbitrary<RefreshTokenRecord> {
  const nowMs = now.getTime();
  const futureExpiryMs = nowMs + 7 * 24 * 60 * 60 * 1000;
  const pastMs = new Date('2024-01-01').getTime();
  return fc.record({
    id: fc.uuid(),
    token: fc.string({ minLength: 32, maxLength: 64 }),
    userId: userIdArb,
    expiresAt: fc.integer({ min: nowMs + 1000, max: futureExpiryMs }).map((ts) => new Date(ts)),
    createdAt: fc.integer({ min: pastMs, max: nowMs }).map((ts) => new Date(ts)),
    revoked: fc.constant(false),
  });
}

/** Generate a revoked refresh token record */
function revokedRefreshTokenArb(now: Date): fc.Arbitrary<RefreshTokenRecord> {
  const nowMs = now.getTime();
  const futureMs = new Date('2030-12-31').getTime();
  const pastMs = new Date('2024-01-01').getTime();
  return fc.record({
    id: fc.uuid(),
    token: fc.string({ minLength: 32, maxLength: 64 }),
    userId: userIdArb,
    expiresAt: fc.integer({ min: nowMs + 1000, max: futureMs }).map((ts) => new Date(ts)),
    createdAt: fc.integer({ min: pastMs, max: nowMs }).map((ts) => new Date(ts)),
    revoked: fc.constant(true),
  });
}

/** Generate an expired refresh token record */
function expiredRefreshTokenArb(now: Date): fc.Arbitrary<RefreshTokenRecord> {
  const nowMs = now.getTime();
  const pastMs = new Date('2024-01-01').getTime();
  return fc.record({
    id: fc.uuid(),
    token: fc.string({ minLength: 32, maxLength: 64 }),
    userId: userIdArb,
    expiresAt: fc.integer({ min: pastMs, max: nowMs - 1000 }).map((ts) => new Date(ts)),
    createdAt: fc.integer({ min: pastMs, max: nowMs - 2000 }).map((ts) => new Date(ts)),
    revoked: fc.constant(false),
  });
}

// ─── Property 20: Token Refresh Rotation ──────────────────────────────

describe('Feature: perfect-world-neo-brutalism, Property 20: Token Refresh Rotation', () => {
  /**
   * **Validates: Requirements 9.3**
   *
   * For any valid refresh token used to obtain a new token pair, the operation
   * SHALL return a new access token (expiry 15 minutes) and a new refresh token
   * (expiry 7 days), AND the original refresh token SHALL become invalid for
   * subsequent use.
   */

  it('valid refresh token produces successful rotation and revokes old token', () => {
    const now = new Date('2025-06-01T12:00:00Z');

    fc.assert(
      fc.property(validRefreshTokenArb(now), (token) => {
        const result = AuthService.performTokenRefresh(token, now);

        // Refresh succeeds
        expect(result.success).toBe(true);
        // Old token is marked as revoked
        expect(result.oldTokenRevoked).toBe(true);
      }),
      { numRuns: 200 }
    );
  });

  it('new refresh token expiry is exactly 7 days from refresh time', () => {
    fc.assert(
      fc.property(dateArb, (now) => {
        const expiry = AuthService.computeRefreshTokenExpiry(now);
        const expectedMs = AUTH.REFRESH_TOKEN_EXPIRY_DAYS * 24 * 60 * 60 * 1000;

        expect(expiry.getTime() - now.getTime()).toBe(expectedMs);
      }),
      { numRuns: 200 }
    );
  });

  it('new access token expiry is exactly 15 minutes (in seconds)', () => {
    const expirySeconds = AuthService.computeAccessTokenExpirySeconds();
    expect(expirySeconds).toBe(AUTH.ACCESS_TOKEN_EXPIRY_MINUTES * 60);
  });

  it('already-revoked token cannot be used for refresh', () => {
    const now = new Date('2025-06-01T12:00:00Z');

    fc.assert(
      fc.property(revokedRefreshTokenArb(now), (token) => {
        const result = AuthService.performTokenRefresh(token, now);

        expect(result.success).toBe(false);
        expect(result.oldTokenRevoked).toBe(false);
        expect(result.error).toBe('Token already revoked');
      }),
      { numRuns: 200 }
    );
  });

  it('expired token cannot be used for refresh', () => {
    const now = new Date('2025-06-01T12:00:00Z');

    fc.assert(
      fc.property(expiredRefreshTokenArb(now), (token) => {
        const result = AuthService.performTokenRefresh(token, now);

        expect(result.success).toBe(false);
        expect(result.oldTokenRevoked).toBe(false);
        expect(result.error).toBe('Token expired');
      }),
      { numRuns: 200 }
    );
  });

  it('null token (not found) cannot be used for refresh', () => {
    const now = new Date('2025-06-01T12:00:00Z');
    const result = AuthService.performTokenRefresh(null, now);

    expect(result.success).toBe(false);
    expect(result.oldTokenRevoked).toBe(false);
    expect(result.error).toBe('Token not found');
  });
});

// ─── Property 21: Account Lock After Failed Attempts ──────────────────

describe('Feature: perfect-world-neo-brutalism, Property 21: Account Lock After Failed Attempts', () => {
  /**
   * **Validates: Requirements 9.5**
   *
   * For any account with N consecutive failed login attempts, the account SHALL
   * be locked if and only if N >= 5. When locked, the lock duration SHALL be
   * 15 minutes. Successful login SHALL reset the failed attempt counter to 0.
   */

  it('account is locked if and only if failed attempts reach 5', () => {
    const now = new Date('2025-06-01T12:00:00Z');

    // Start with an unlocked user with 0-9 failed attempts
    const userArb = userAuthStateArb({
      failedAttempts: fc.integer({ min: 0, max: 9 }),
      lockedUntil: fc.constant(null),
    });

    fc.assert(
      fc.property(userArb, (user) => {
        // Simulate a failed login
        const { result, updatedUser } = AuthService.processLoginAttempt(user, false, now);

        const newAttempts = user.failedLoginAttempts + 1;

        // The result should reflect the new attempt count
        expect(result.success).toBe(false);
        expect(result.failedAttempts).toBe(newAttempts);

        // Account should be locked if and only if attempts >= 5
        if (newAttempts >= AUTH.MAX_FAILED_LOGIN_ATTEMPTS) {
          expect(result.locked).toBe(true);
          expect(updatedUser.lockedUntil).not.toBeNull();
        } else {
          expect(result.locked).toBe(false);
        }
      }),
      { numRuns: 200 }
    );
  });

  it('lock duration is exactly 15 minutes', () => {
    // User with exactly 4 failed attempts (next failure will lock)
    const userArb = userAuthStateArb({
      failedAttempts: fc.integer({
        min: AUTH.MAX_FAILED_LOGIN_ATTEMPTS - 1,
        max: AUTH.MAX_FAILED_LOGIN_ATTEMPTS - 1,
      }),
      lockedUntil: fc.constant(null),
    });

    // Use integer timestamps to avoid Date(NaN) issues
    const timestampArb = fc.integer({
      min: new Date('2024-01-01').getTime(),
      max: new Date('2030-12-31').getTime(),
    });

    fc.assert(
      fc.property(userArb, timestampArb, (user, timestamp) => {
        const now = new Date(timestamp);
        const { updatedUser } = AuthService.processLoginAttempt(user, false, now);

        expect(updatedUser.lockedUntil).not.toBeNull();
        const lockDurationMs = updatedUser.lockedUntil!.getTime() - now.getTime();
        const expectedMs = AUTH.ACCOUNT_LOCK_DURATION_MINUTES * 60 * 1000;

        expect(lockDurationMs).toBe(expectedMs);
      }),
      { numRuns: 200 }
    );
  });

  it('successful login resets failed attempt counter to 0', () => {
    const now = new Date('2025-06-01T12:00:00Z');

    // User with any number of failed attempts (but not locked)
    const userArb = userAuthStateArb({
      failedAttempts: fc.integer({ min: 0, max: AUTH.MAX_FAILED_LOGIN_ATTEMPTS - 1 }),
      lockedUntil: fc.constant(null),
    });

    fc.assert(
      fc.property(userArb, (user) => {
        const { result, updatedUser } = AuthService.processLoginAttempt(user, true, now);

        expect(result.success).toBe(true);
        expect(result.locked).toBe(false);
        expect(result.failedAttempts).toBe(0);
        expect(updatedUser.failedLoginAttempts).toBe(0);
        expect(updatedUser.lockedUntil).toBeNull();
      }),
      { numRuns: 200 }
    );
  });

  it('locked account rejects login even with correct password', () => {
    // User with lock in the future
    const now = new Date('2025-06-01T12:15:00Z');

    // Generate a lockedUntil date that is definitely in the future relative to now
    const futureLockedUntilArb = fc.integer({
      min: now.getTime() + 1000,
      max: now.getTime() + AUTH.ACCOUNT_LOCK_DURATION_MINUTES * 60 * 1000,
    }).map((ts) => new Date(ts));

    const lockedUserArb = fc.record({
      id: userIdArb,
      email: fc.emailAddress(),
      passwordHash: fc.string({ minLength: 60, maxLength: 60 }),
      failedLoginAttempts: fc.integer({ min: AUTH.MAX_FAILED_LOGIN_ATTEMPTS, max: 20 }),
      lockedUntil: futureLockedUntilArb,
      totpEnabled: fc.boolean(),
    });

    fc.assert(
      fc.property(lockedUserArb, fc.boolean(), (user, passwordCorrect) => {
        const { result } = AuthService.processLoginAttempt(user, passwordCorrect, now);

        expect(result.success).toBe(false);
        expect(result.locked).toBe(true);
      }),
      { numRuns: 200 }
    );
  });

  it('account lock expires after the lock duration', () => {
    // User was locked at some point in the past
    const lockTime = new Date('2025-06-01T12:00:00Z');
    const lockExpiry = new Date(
      lockTime.getTime() + AUTH.ACCOUNT_LOCK_DURATION_MINUTES * 60 * 1000,
    );

    // Now is after the lock expiry
    const afterLockArb = fc.date({
      min: lockExpiry,
      max: new Date('2030-12-31'),
    });

    const lockedUserArb = userAuthStateArb({
      failedAttempts: fc.constant(AUTH.MAX_FAILED_LOGIN_ATTEMPTS),
      lockedUntil: fc.constant(lockExpiry),
    });

    fc.assert(
      fc.property(lockedUserArb, afterLockArb, (user, now) => {
        // Lock should have expired
        expect(AuthService.isAccountLocked(user, now)).toBe(false);

        // Correct password should succeed
        const { result } = AuthService.processLoginAttempt(user, true, now);
        expect(result.success).toBe(true);
        expect(result.failedAttempts).toBe(0);
      }),
      { numRuns: 200 }
    );
  });

  it('consecutive failed attempts accumulate correctly', () => {
    const now = new Date('2025-06-01T12:00:00Z');

    // Start with 0 failed attempts
    const initialUserArb = userAuthStateArb({
      failedAttempts: fc.constant(0),
      lockedUntil: fc.constant(null),
    });

    // Number of consecutive failures to simulate (1-7)
    const failCountArb = fc.integer({ min: 1, max: 7 });

    fc.assert(
      fc.property(initialUserArb, failCountArb, (initialUser, failCount) => {
        let currentUser = { ...initialUser };

        for (let i = 0; i < failCount; i++) {
          // Once locked, further attempts don't increment the counter
          if (AuthService.isAccountLocked(currentUser, now)) {
            break;
          }
          const { updatedUser } = AuthService.processLoginAttempt(currentUser, false, now);
          currentUser = updatedUser;
        }

        // After N failures (up to lock threshold), failedLoginAttempts should be min(N, MAX)
        const expectedAttempts = Math.min(failCount, AUTH.MAX_FAILED_LOGIN_ATTEMPTS);
        expect(currentUser.failedLoginAttempts).toBe(expectedAttempts);

        // Should be locked if and only if attempts >= 5
        if (expectedAttempts >= AUTH.MAX_FAILED_LOGIN_ATTEMPTS) {
          expect(currentUser.lockedUntil).not.toBeNull();
        } else {
          expect(currentUser.lockedUntil).toBeNull();
        }
      }),
      { numRuns: 200 }
    );
  });
});

// ─── Property 22: Token Invalidation on Security Change ───────────────

describe('Feature: perfect-world-neo-brutalism, Property 22: Token Invalidation on Security Change', () => {
  /**
   * **Validates: Requirements 9.10**
   *
   * For any account with one or more active refresh tokens, when the user
   * changes their password or enables 2FA, ALL existing refresh tokens for
   * that account SHALL become invalid.
   */

  it('password change invalidates all active tokens for the user', () => {
    const now = new Date('2025-06-01T12:00:00Z');

    // Generate a user ID and multiple tokens for that user
    const scenarioArb = fc.tuple(
      userIdArb,
      fc.integer({ min: 1, max: 10 }),
    ).chain(([userId, tokenCount]) => {
      const tokensArb = fc.array(
        validRefreshTokenArb(now).map((t) => ({ ...t, userId })),
        { minLength: tokenCount, maxLength: tokenCount },
      );
      return fc.tuple(fc.constant(userId), tokensArb);
    });

    fc.assert(
      fc.property(scenarioArb, ([userId, tokens]) => {
        // Password change should trigger invalidation
        expect(AuthService.shouldInvalidateTokens('password_change')).toBe(true);

        // All tokens for this user should be identified for invalidation
        const toInvalidate = AuthService.computeTokensToInvalidate(tokens, userId);
        expect(toInvalidate.length).toBe(tokens.length);

        // Every token in the result belongs to the user
        for (const token of toInvalidate) {
          expect(token.userId).toBe(userId);
          expect(token.revoked).toBe(false);
        }
      }),
      { numRuns: 200 }
    );
  });

  it('enabling 2FA invalidates all active tokens for the user', () => {
    const now = new Date('2025-06-01T12:00:00Z');

    const scenarioArb = fc.tuple(
      userIdArb,
      fc.integer({ min: 1, max: 10 }),
    ).chain(([userId, tokenCount]) => {
      const tokensArb = fc.array(
        validRefreshTokenArb(now).map((t) => ({ ...t, userId })),
        { minLength: tokenCount, maxLength: tokenCount },
      );
      return fc.tuple(fc.constant(userId), tokensArb);
    });

    fc.assert(
      fc.property(scenarioArb, ([userId, tokens]) => {
        // 2FA enable should trigger invalidation
        expect(AuthService.shouldInvalidateTokens('enable_2fa')).toBe(true);

        // All tokens for this user should be identified for invalidation
        const toInvalidate = AuthService.computeTokensToInvalidate(tokens, userId);
        expect(toInvalidate.length).toBe(tokens.length);
      }),
      { numRuns: 200 }
    );
  });

  it('non-security events do not trigger token invalidation', () => {
    const nonSecurityEvents: Array<'profile_update' | 'email_change'> = [
      'profile_update',
      'email_change',
    ];

    for (const event of nonSecurityEvents) {
      expect(AuthService.shouldInvalidateTokens(event)).toBe(false);
    }
  });

  it('only tokens belonging to the specific user are invalidated', () => {
    const now = new Date('2025-06-01T12:00:00Z');

    // Generate tokens for multiple users
    const scenarioArb = fc.tuple(
      userIdArb,
      userIdArb,
    ).filter(([a, b]) => a !== b)
      .chain(([targetUserId, otherUserId]) => {
        const targetTokensArb = fc.array(
          validRefreshTokenArb(now).map((t) => ({ ...t, userId: targetUserId })),
          { minLength: 1, maxLength: 5 },
        );
        const otherTokensArb = fc.array(
          validRefreshTokenArb(now).map((t) => ({ ...t, userId: otherUserId })),
          { minLength: 1, maxLength: 5 },
        );
        return fc.tuple(
          fc.constant(targetUserId),
          fc.constant(otherUserId),
          targetTokensArb,
          otherTokensArb,
        );
      });

    fc.assert(
      fc.property(scenarioArb, ([targetUserId, otherUserId, targetTokens, otherTokens]) => {
        const allTokens = [...targetTokens, ...otherTokens];

        const toInvalidate = AuthService.computeTokensToInvalidate(allTokens, targetUserId);

        // Only target user's tokens are invalidated
        expect(toInvalidate.length).toBe(targetTokens.length);
        for (const token of toInvalidate) {
          expect(token.userId).toBe(targetUserId);
        }

        // Other user's tokens are NOT invalidated
        const otherInvalidated = AuthService.computeTokensToInvalidate(allTokens, otherUserId);
        expect(otherInvalidated.length).toBe(otherTokens.length);
        for (const token of otherInvalidated) {
          expect(token.userId).toBe(otherUserId);
        }
      }),
      { numRuns: 200 }
    );
  });

  it('already-revoked tokens are not included in invalidation set', () => {
    const now = new Date('2025-06-01T12:00:00Z');

    const scenarioArb = userIdArb.chain((userId) => {
      const activeTokensArb = fc.array(
        validRefreshTokenArb(now).map((t) => ({ ...t, userId })),
        { minLength: 1, maxLength: 5 },
      );
      const revokedTokensArb = fc.array(
        revokedRefreshTokenArb(now).map((t) => ({ ...t, userId })),
        { minLength: 1, maxLength: 5 },
      );
      return fc.tuple(fc.constant(userId), activeTokensArb, revokedTokensArb);
    });

    fc.assert(
      fc.property(scenarioArb, ([userId, activeTokens, revokedTokens]) => {
        const allTokens = [...activeTokens, ...revokedTokens];

        const toInvalidate = AuthService.computeTokensToInvalidate(allTokens, userId);

        // Only active (non-revoked) tokens should be in the invalidation set
        expect(toInvalidate.length).toBe(activeTokens.length);
        for (const token of toInvalidate) {
          expect(token.revoked).toBe(false);
        }
      }),
      { numRuns: 200 }
    );
  });
});

import {
  Injectable,
