  ForbiddenException,
  BadRequestException,
} from '@nestjs/common';
import { DatabaseService } from '../database/database.service';
import { GuildSearchDto, UpdateGuildSettingsDto, MemberAction } from './dto';
import { GuildRank, GuildActivityType } from '@perfect-world/shared';

@Injectable()
export class GuildService {
  constructor(private readonly db: DatabaseService) {}

  /**
   * Get guild profile with territory count
   * Requirement 18.1: guild name, emblem, description (max 500), member count, territory count, creation date
   */
  async getGuildProfile(guildId: string) {
    const guild = await this.db.guild.findUnique({
      where: { id: guildId },
      include: {
        _count: {
          select: { territories: true },
        },
      },
    });

    if (!guild) {
      throw new NotFoundException('Guild not found');
    }

    return {
      id: guild.id,
      name: guild.name,
      description: guild.description,
      emblemUrl: guild.emblemUrl,
      leaderId: guild.leaderId,
      memberCount: guild.memberCount,
      territoryCount: guild._count.territories,
      isRecruiting: guild.isRecruiting,
      minLevel: guild.minLevel,
      createdAt: guild.createdAt.toISOString(),
    };
  }

  /**
   * Get guild member roster with pagination (50/page)
   * Requirement 18.2: member name, rank, class, level, last online time, contribution score
   */
  async getMembers(guildId: string, page: number = 1) {
    const pageSize = 50;
    const skip = (page - 1) * pageSize;

    const guild = await this.db.guild.findUnique({ where: { id: guildId } });
    if (!guild) {
      throw new NotFoundException('Guild not found');
    }

    const [members, total] = await Promise.all([
      this.db.character.findMany({
        where: { guildId },
        select: {
          id: true,
          name: true,
          class: true,
          level: true,
          guildRank: true,
          createdAt: true,
          updatedAt: true,
        },
        orderBy: [
          { guildRank: 'asc' },
          { level: 'desc' },
        ],
        skip,
        take: pageSize,
      }),
      this.db.character.count({ where: { guildId } }),
    ]);

    return {
      data: members.map((m) => ({
        id: m.id,
        characterName: m.name,
        class: m.class,
        level: m.level,
        rank: m.guildRank,
        lastOnline: m.updatedAt.toISOString(),
        joinedAt: m.createdAt.toISOString(),
      })),
      total,
      page,
      pageSize,
      totalPages: Math.ceil(total / pageSize),
    };
  }

  /**
   * Get guild activity feed (50 most recent)
   * Requirement 18.8: member join/leave, territory war results, leader announcements
   */
  async getActivityFeed(guildId: string, limit: number = 50) {
    const guild = await this.db.guild.findUnique({ where: { id: guildId } });
    if (!guild) {
      throw new NotFoundException('Guild not found');
    }

    const activities = await this.db.guildActivity.findMany({
      where: { guildId },
      orderBy: { createdAt: 'desc' },
      take: limit,
    });

    return activities.map((a) => ({
      id: a.id,
      guildId: a.guildId,
      type: a.type,
      actorName: a.actorName,
      details: a.details,
      createdAt: a.createdAt.toISOString(),
    }));
  }

  /**
   * Search guilds with filters
   * Requirement 18.3: filters for min level, territory count, recruitment status, 20 results/page
   */
  async searchGuilds(filters: GuildSearchDto) {
    const page = filters.page ?? 1;
    const pageSize = Math.min(filters.pageSize ?? 20, 20);
    const skip = (page - 1) * pageSize;

    const where: Record<string, unknown> = {};

    if (filters.name) {
      where.name = { contains: filters.name, mode: 'insensitive' };
    }

    if (filters.minLevel !== undefined) {
      where.minLevel = { gte: filters.minLevel };
    }

    if (filters.isRecruiting !== undefined) {
      where.isRecruiting = filters.isRecruiting;
    }

    // Territory count filter: use having on relation count
    if (filters.minTerritoryCount !== undefined && filters.minTerritoryCount > 0) {
      where.territories = { some: {} };
    }

    const [guilds, total] = await Promise.all([
      this.db.guild.findMany({
        where,
        include: {
          _count: {
            select: { territories: true },
          },
        },
        orderBy: { memberCount: 'desc' },
        skip,
        take: pageSize,
      }),
      this.db.guild.count({ where }),
    ]);

    // Post-filter by territory count if needed
    let filteredGuilds = guilds;
    if (filters.minTerritoryCount !== undefined && filters.minTerritoryCount > 0) {
      filteredGuilds = guilds.filter(
        (g) => g._count.territories >= filters.minTerritoryCount!,
      );
    }

    return {
      data: filteredGuilds.map((g) => ({
        id: g.id,
        name: g.name,
        emblemUrl: g.emblemUrl,
        memberCount: g.memberCount,
        territoryCount: g._count.territories,
        isRecruiting: g.isRecruiting,
        minLevel: g.minLevel,
      })),
      total: filters.minTerritoryCount ? filteredGuilds.length : total,
      page,
      pageSize,
      totalPages: Math.ceil(
        (filters.minTerritoryCount ? filteredGuilds.length : total) / pageSize,
      ),
    };
  }

  /**
   * Manage guild member (promote, demote, remove)
   * Requirement 18.6: leader only, apply within 5 seconds, notify affected member
   * Requirement 18.7: reject if non-leader attempts management action
   */
  async manageMember(
    guildId: string,
    requesterId: string,
    memberId: string,
    action: MemberAction,
  ) {
    // Verify the guild exists
    const guild = await this.db.guild.findUnique({ where: { id: guildId } });
    if (!guild) {
      throw new NotFoundException('Guild not found');
    }

    // Verify the requester is the guild leader
    const requester = await this.db.character.findFirst({
      where: { id: requesterId, guildId },
    });

    if (!requester || requester.guildRank !== GuildRank.LEADER) {
      throw new ForbiddenException(
        'Insufficient guild rank permissions. Only the guild leader can manage members.',
      );
    }

    // Verify the target member exists in the guild
    const member = await this.db.character.findFirst({
      where: { id: memberId, guildId },
    });

    if (!member) {
      throw new NotFoundException('Member not found in this guild');
    }

    // Cannot manage yourself
    if (memberId === requesterId) {
      throw new BadRequestException('Cannot perform this action on yourself');
    }

    switch (action) {
      case MemberAction.PROMOTE:
        return this.promoteMember(guildId, member);
      case MemberAction.DEMOTE:
        return this.demoteMember(guildId, member);
      case MemberAction.REMOVE:
        return this.removeMember(guildId, member);
      default:
        throw new BadRequestException('Invalid action');
    }
  }

  private async promoteMember(
    guildId: string,
    member: { id: string; name: string; guildRank: string | null },
  ) {
    const rankOrder = [
      GuildRank.RECRUIT,
      GuildRank.MEMBER,
      GuildRank.VETERAN,
      GuildRank.OFFICER,
    ];

    const currentIndex = rankOrder.indexOf(member.guildRank as GuildRank);
    if (currentIndex === -1 || currentIndex >= rankOrder.length - 1) {
      throw new BadRequestException('Member cannot be promoted further');
    }

    const newRank = rankOrder[currentIndex + 1];

    await this.db.character.update({
      where: { id: member.id },
      data: { guildRank: newRank },
    });

    // Log activity
    await this.db.guildActivity.create({
      data: {
        guildId,
        type: GuildActivityType.MEMBER_PROMOTED,
        actorName: member.name,
        details: { newRank },
      },
    });

    return { success: true, newRank };
  }

  private async demoteMember(
    guildId: string,
    member: { id: string; name: string; guildRank: string | null },
  ) {
    const rankOrder = [
      GuildRank.RECRUIT,
      GuildRank.MEMBER,
      GuildRank.VETERAN,
      GuildRank.OFFICER,
    ];

    const currentIndex = rankOrder.indexOf(member.guildRank as GuildRank);
    if (currentIndex <= 0) {
      throw new BadRequestException('Member cannot be demoted further');
    }

    const newRank = rankOrder[currentIndex - 1];

    await this.db.character.update({
      where: { id: member.id },
      data: { guildRank: newRank },
    });

    // Log activity
    await this.db.guildActivity.create({
      data: {
        guildId,
        type: GuildActivityType.MEMBER_DEMOTED,
        actorName: member.name,
        details: { newRank },
      },
    });

    return { success: true, newRank };
  }

  private async removeMember(
    guildId: string,
    member: { id: string; name: string; guildRank: string | null },
  ) {
    await this.db.character.update({
      where: { id: member.id },
      data: { guildId: null, guildRank: null },
    });

    // Decrement member count
    await this.db.guild.update({
      where: { id: guildId },
      data: { memberCount: { decrement: 1 } },
    });

    // Log activity
    await this.db.guildActivity.create({
      data: {
        guildId,
        type: GuildActivityType.MEMBER_KICKED,
        actorName: member.name,
        details: { reason: 'Removed by guild leader' },
      },
    });

    return { success: true, action: 'removed' };
  }

  /**
   * Update guild settings
   * Requirement 18.4: apply changes within 5 seconds, display confirmation
   */
  async updateSettings(
    guildId: string,
    requesterId: string,
    data: UpdateGuildSettingsDto,
  ) {
    // Verify the guild exists
    const guild = await this.db.guild.findUnique({ where: { id: guildId } });
    if (!guild) {
      throw new NotFoundException('Guild not found');
    }

    // Verify the requester is the guild leader
    const requester = await this.db.character.findFirst({
      where: { id: requesterId, guildId },
    });

    if (!requester || requester.guildRank !== GuildRank.LEADER) {
      throw new ForbiddenException(
        'Insufficient guild rank permissions. Only the guild leader can update settings.',
      );
    }

    // Truncate description to 500 chars if needed
    const updateData: Record<string, unknown> = {};
    if (data.name !== undefined) updateData.name = data.name;
    if (data.description !== undefined) {
      updateData.description = data.description.slice(0, 500);
    }
    if (data.emblemUrl !== undefined) updateData.emblemUrl = data.emblemUrl;
    if (data.isRecruiting !== undefined) updateData.isRecruiting = data.isRecruiting;
    if (data.minLevel !== undefined) updateData.minLevel = data.minLevel;

    const updated = await this.db.guild.update({
      where: { id: guildId },
      data: updateData,
    });

    return {
      success: true,
      guild: {
        id: updated.id,
        name: updated.name,
        description: updated.description,
        emblemUrl: updated.emblemUrl,
        isRecruiting: updated.isRecruiting,
        minLevel: updated.minLevel,
      },
    };
  }
}

import {
  Controller,
  Get,
  Put,
  Post,
  Param,
  Query,
  Body,
  UseGuards,
  Request,
} from '@nestjs/common';
import { GuildService } from './guild.service';
import { GuildSearchDto, UpdateGuildSettingsDto, ManageMemberDto } from './dto';
import { JwtAuthGuard } from '../common/guards/jwt-auth.guard';
import { Public } from '../common/decorators/public.decorator';
import type { JwtPayload } from '../common/guards/jwt-auth.guard';

@Controller('guilds')
@UseGuards(JwtAuthGuard)
export class GuildController {
  constructor(private readonly guildService: GuildService) {}

  /**
   * GET /api/guilds/search
   * Search guilds with filters (min level, territory count, recruitment status)
   * Returns max 20 results per page
   * Requirement 18.3, 18.5
   */
  @Get('search')
  @Public()
  async searchGuilds(@Query() filters: GuildSearchDto) {
    return this.guildService.searchGuilds(filters);
  }

  /**
   * GET /api/guilds/:guildId
   * Get guild profile with name, emblem, description, member count, territory count, creation date
   * Requirement 18.1
   */
  @Get(':guildId')
  @Public()
  async getGuildProfile(@Param('guildId') guildId: string) {
    return this.guildService.getGuildProfile(guildId);
  }

  /**
   * GET /api/guilds/:guildId/members
   * Get guild member roster paginated at 50/page
   * Requirement 18.2
   */
  @Get(':guildId/members')
  @Public()
  async getMembers(
    @Param('guildId') guildId: string,
    @Query('page') page?: string,
  ) {
    const pageNum = page ? parseInt(page, 10) : 1;
    return this.guildService.getMembers(guildId, pageNum);
  }

  /**
   * GET /api/guilds/:guildId/activity
   * Get guild activity feed (50 most recent entries)
   * Requirement 18.8
   */
  @Get(':guildId/activity')
  @Public()
  async getActivityFeed(
    @Param('guildId') guildId: string,
    @Query('limit') limit?: string,
  ) {
    const limitNum = limit ? Math.min(parseInt(limit, 10), 50) : 50;
    return this.guildService.getActivityFeed(guildId, limitNum);
  }

  /**
   * PUT /api/guilds/:guildId/settings
   * Update guild settings (leader only)
   * Requirement 18.4
   */
  @Put(':guildId/settings')
  async updateSettings(
    @Param('guildId') guildId: string,
    @Body() data: UpdateGuildSettingsDto,
    @Request() req: { user: JwtPayload },
    @Query('characterId') characterId: string,
  ) {
    return this.guildService.updateSettings(guildId, characterId, data);
  }

  /**
   * POST /api/guilds/:guildId/members/manage
   * Manage guild member (promote, demote, remove) - leader only
   * Requirements 18.6, 18.7
   */
  @Post(':guildId/members/manage')
  async manageMember(
    @Param('guildId') guildId: string,
    @Body() data: ManageMemberDto,
    @Request() req: { user: JwtPayload },
    @Query('characterId') characterId: string,
  ) {
    return this.guildService.manageMember(
      guildId,
      characterId,
      data.memberId,
      data.action,
    );
  }
}

import { Module } from '@nestjs/common';
import { GuildController } from './guild.controller';
import { GuildService } from './guild.service';

@Module({
  controllers: [GuildController],
  providers: [GuildService],
  exports: [GuildService],
})
export class GuildModule {}

import { describe, it, expect } from 'vitest';
import fc from 'fast-check';
import { GuildRank } from '@perfect-world/shared';
import { MemberAction } from './dto';

/**
 * Property-Based Tests for Guild Service
 *
 * Validates: Requirements 18.1, 18.3, 18.7
 */

// ─── Pure Logic Extracted for Property Testing ────────────────────────

/**
 * Guild description truncation logic (mirrors guild.service.ts updateSettings)
 * Requirement 18.1: description max 500 characters
 */
function truncateGuildDescription(description: string): string {
  return description.slice(0, 500);
}

/**
 * Guild search filter logic (mirrors guild.service.ts searchGuilds)
 * Requirement 18.3: filters for min level, territory count, recruitment status
 */
interface GuildData {
  id: string;
  name: string;
  memberCount: number;
  territoryCount: number;
  isRecruiting: boolean;
  minLevel: number;
}

interface GuildSearchFilters {
  name?: string;
  minLevel?: number;
  minTerritoryCount?: number;
  isRecruiting?: boolean;
  page?: number;
  pageSize?: number;
}

function filterGuilds(guilds: GuildData[], filters: GuildSearchFilters): GuildData[] {
  let results = [...guilds];

  if (filters.name !== undefined) {
    results = results.filter((g) =>
      g.name.toLowerCase().includes(filters.name!.toLowerCase()),
    );
  }

  if (filters.minLevel !== undefined) {
    results = results.filter((g) => g.minLevel >= filters.minLevel!);
  }

  if (filters.minTerritoryCount !== undefined && filters.minTerritoryCount > 0) {
    results = results.filter((g) => g.territoryCount >= filters.minTerritoryCount!);
  }

  if (filters.isRecruiting !== undefined) {
    results = results.filter((g) => g.isRecruiting === filters.isRecruiting);
  }

  return results;
}

function paginateResults(results: GuildData[], page: number, pageSize: number): GuildData[] {
  const effectivePageSize = Math.min(pageSize, 20);
  const skip = (page - 1) * effectivePageSize;
  return results.slice(skip, skip + effectivePageSize);
}

/**
 * Guild permission check logic (mirrors guild.service.ts manageMember)
 * Requirement 18.7: only guild leader can perform management actions
 */
type ManagementAction = 'PROMOTE' | 'DEMOTE' | 'REMOVE';

interface PermissionCheckResult {
  allowed: boolean;
  error?: string;
}

function checkGuildManagementPermission(
  requesterRank: GuildRank | null,
  action: ManagementAction,
): PermissionCheckResult {
  if (requesterRank !== GuildRank.LEADER) {
    return {
      allowed: false,
      error: 'Insufficient guild rank permissions. Only the guild leader can manage members.',
    };
  }
  return { allowed: true };
}

// ─── Arbitraries ──────────────────────────────────────────────────────

/** Generate an arbitrary string of any length (including very long ones) */
const arbitraryDescription = fc.string({ minLength: 0, maxLength: 2000 });

/** Generate a guild data object */
const guildDataArb: fc.Arbitrary<GuildData> = fc.record({
  id: fc.uuid(),
  name: fc.string({ minLength: 1, maxLength: 100 }),
  memberCount: fc.integer({ min: 1, max: 500 }),
  territoryCount: fc.integer({ min: 0, max: 50 }),
  isRecruiting: fc.boolean(),
  minLevel: fc.integer({ min: 1, max: 150 }),
});

/** Generate a list of guilds */
const guildListArb = fc.array(guildDataArb, { minLength: 0, maxLength: 100 });

/** Generate search filters */
const searchFiltersArb: fc.Arbitrary<GuildSearchFilters> = fc.record({
  name: fc.option(fc.string({ minLength: 1, maxLength: 50 }), { nil: undefined }),
  minLevel: fc.option(fc.integer({ min: 1, max: 150 }), { nil: undefined }),
  minTerritoryCount: fc.option(fc.integer({ min: 0, max: 50 }), { nil: undefined }),
  isRecruiting: fc.option(fc.boolean(), { nil: undefined }),
  page: fc.option(fc.integer({ min: 1, max: 10 }), { nil: undefined }),
  pageSize: fc.option(fc.integer({ min: 1, max: 50 }), { nil: undefined }),
});

/** Generate a non-leader guild rank */
const nonLeaderRankArb: fc.Arbitrary<GuildRank> = fc.constantFrom(
  GuildRank.OFFICER,
  GuildRank.VETERAN,
  GuildRank.MEMBER,
  GuildRank.RECRUIT,
);

/** Generate any guild rank */
const anyRankArb: fc.Arbitrary<GuildRank> = fc.constantFrom(
  GuildRank.LEADER,
  GuildRank.OFFICER,
  GuildRank.VETERAN,
  GuildRank.MEMBER,
  GuildRank.RECRUIT,
);

/** Generate a management action */
const managementActionArb: fc.Arbitrary<ManagementAction> = fc.constantFrom(
  'PROMOTE',
  'DEMOTE',
  'REMOVE',
);

// ─── Property 27: Guild Description Truncation ────────────────────────

describe('Feature: perfect-world-neo-brutalism, Property 27: Guild Description Truncation', () => {
  /**
   * **Validates: Requirements 18.1**
   *
   * For any guild with a description string of arbitrary length, the displayed
   * description SHALL never exceed 500 characters.
   */

  it('truncated description never exceeds 500 characters', () => {
    fc.assert(
      fc.property(arbitraryDescription, (description) => {
        const result = truncateGuildDescription(description);
        expect(result.length).toBeLessThanOrEqual(500);
      }),
      { numRuns: 500 },
    );
  });

  it('descriptions of 500 characters or fewer are preserved exactly', () => {
    const shortDescriptionArb = fc.string({ minLength: 0, maxLength: 500 });

    fc.assert(
      fc.property(shortDescriptionArb, (description) => {
        const result = truncateGuildDescription(description);
        expect(result).toBe(description);
      }),
      { numRuns: 500 },
    );
  });

  it('descriptions longer than 500 characters are truncated to exactly 500', () => {
    const longDescriptionArb = fc.string({ minLength: 501, maxLength: 2000 });

    fc.assert(
      fc.property(longDescriptionArb, (description) => {
        const result = truncateGuildDescription(description);
        expect(result.length).toBe(500);
      }),
      { numRuns: 500 },
    );
  });

  it('truncated description is a prefix of the original', () => {
    fc.assert(
      fc.property(arbitraryDescription, (description) => {
        const result = truncateGuildDescription(description);
        expect(description.startsWith(result)).toBe(true);
      }),
      { numRuns: 500 },
    );
  });
});

// ─── Property 28: Guild Search Filter Correctness ─────────────────────

describe('Feature: perfect-world-neo-brutalism, Property 28: Guild Search Filter Correctness', () => {
  /**
   * **Validates: Requirements 18.3**
   *
   * For any guild search with active filters (minimum level, territory count,
   * recruitment status), all returned results SHALL satisfy every active filter
   * condition, and no guild satisfying all conditions SHALL be excluded from
   * results. Each page SHALL contain at most 20 results.
   */

  it('all returned results satisfy every active filter condition', () => {
    fc.assert(
      fc.property(guildListArb, searchFiltersArb, (guilds, filters) => {
        const results = filterGuilds(guilds, filters);

        for (const guild of results) {
          if (filters.name !== undefined) {
            expect(guild.name.toLowerCase()).toContain(filters.name.toLowerCase());
          }
          if (filters.minLevel !== undefined) {
            expect(guild.minLevel).toBeGreaterThanOrEqual(filters.minLevel);
          }
          if (filters.minTerritoryCount !== undefined && filters.minTerritoryCount > 0) {
            expect(guild.territoryCount).toBeGreaterThanOrEqual(filters.minTerritoryCount);
          }
          if (filters.isRecruiting !== undefined) {
            expect(guild.isRecruiting).toBe(filters.isRecruiting);
          }
        }
      }),
      { numRuns: 500 },
    );
  });

  it('no guild satisfying all conditions is excluded from results', () => {
    fc.assert(
      fc.property(guildListArb, searchFiltersArb, (guilds, filters) => {
        const results = filterGuilds(guilds, filters);

        // Check that every guild in the original list that satisfies all filters is in results
        for (const guild of guilds) {
          let satisfiesAll = true;

          if (filters.name !== undefined) {
            if (!guild.name.toLowerCase().includes(filters.name.toLowerCase())) {
              satisfiesAll = false;
            }
          }
          if (filters.minLevel !== undefined) {
            if (guild.minLevel < filters.minLevel) {
              satisfiesAll = false;
            }
          }
          if (filters.minTerritoryCount !== undefined && filters.minTerritoryCount > 0) {
            if (guild.territoryCount < filters.minTerritoryCount) {
              satisfiesAll = false;
            }
          }
          if (filters.isRecruiting !== undefined) {
            if (guild.isRecruiting !== filters.isRecruiting) {
              satisfiesAll = false;
            }
          }

          if (satisfiesAll) {
            expect(results).toContainEqual(guild);
          }
        }
      }),
      { numRuns: 500 },
    );
  });

  it('each page contains at most 20 results', () => {
    fc.assert(
      fc.property(
        guildListArb,
        fc.integer({ min: 1, max: 10 }),
        fc.integer({ min: 1, max: 50 }),
        (guilds, page, requestedPageSize) => {
          const paginated = paginateResults(guilds, page, requestedPageSize);
          expect(paginated.length).toBeLessThanOrEqual(20);
        },
      ),
      { numRuns: 500 },
    );
  });

  it('page size is capped at 20 regardless of requested size', () => {
    // Generate a large guild list to ensure we have enough data
    const largeGuildListArb = fc.array(guildDataArb, { minLength: 50, maxLength: 100 });

    fc.assert(
      fc.property(
        largeGuildListArb,
        fc.integer({ min: 21, max: 100 }),
        (guilds, requestedPageSize) => {
          const paginated = paginateResults(guilds, 1, requestedPageSize);
          expect(paginated.length).toBeLessThanOrEqual(20);
        },
      ),
      { numRuns: 200 },
    );
  });
});

// ─── Property 29: Guild Permission Enforcement ────────────────────────

describe('Feature: perfect-world-neo-brutalism, Property 29: Guild Permission Enforcement', () => {
  /**
   * **Validates: Requirements 18.7**
   *
   * For any guild member with rank below LEADER attempting a management action
   * (promote, demote, or remove another member), the action SHALL be rejected
   * with a permission error.
   */

  it('non-leader ranks are always rejected for any management action', () => {
    fc.assert(
      fc.property(nonLeaderRankArb, managementActionArb, (rank, action) => {
        const result = checkGuildManagementPermission(rank, action);
        expect(result.allowed).toBe(false);
        expect(result.error).toBeDefined();
        expect(result.error).toContain('guild leader');
      }),
      { numRuns: 200 },
    );
  });

  it('leader rank is always allowed for any management action', () => {
    fc.assert(
      fc.property(managementActionArb, (action) => {
        const result = checkGuildManagementPermission(GuildRank.LEADER, action);
        expect(result.allowed).toBe(true);
        expect(result.error).toBeUndefined();
      }),
      { numRuns: 200 },
    );
  });

  it('null rank (not in guild) is rejected for any management action', () => {
    fc.assert(
      fc.property(managementActionArb, (action) => {
        const result = checkGuildManagementPermission(null, action);
        expect(result.allowed).toBe(false);
        expect(result.error).toBeDefined();
      }),
      { numRuns: 200 },
    );
  });

  it('permission check is deterministic for any rank and action combination', () => {
    fc.assert(
      fc.property(anyRankArb, managementActionArb, (rank, action) => {
        const result1 = checkGuildManagementPermission(rank, action);
        const result2 = checkGuildManagementPermission(rank, action);
        expect(result1.allowed).toBe(result2.allowed);
        expect(result1.error).toBe(result2.error);
      }),
      { numRuns: 200 },
    );
  });

  it('only LEADER rank is allowed - all other ranks are rejected', () => {
    fc.assert(
      fc.property(anyRankArb, managementActionArb, (rank, action) => {
        const result = checkGuildManagementPermission(rank, action);
        if (rank === GuildRank.LEADER) {
          expect(result.allowed).toBe(true);
        } else {
          expect(result.allowed).toBe(false);
        }
      }),
      { numRuns: 200 },
    );
  });
});

import { describe, it, expect, beforeEach, vi } from 'vitest';
import { NotFoundException, ForbiddenException, BadRequestException } from '@nestjs/common';
import { GuildService } from './guild.service';
import { MemberAction } from './dto';
import { GuildRank, GuildActivityType } from '@perfect-world/shared';

function createMockDb() {
  return {
    guild: {
      findUnique: vi.fn(),
      findMany: vi.fn(),
      count: vi.fn(),
      update: vi.fn(),
    },
    character: {
      findMany: vi.fn(),
      findFirst: vi.fn(),
      count: vi.fn(),
      update: vi.fn(),
    },
    guildActivity: {
      findMany: vi.fn(),
      create: vi.fn(),
    },
  } as any;
}

