import { Injectable } from '@nestjs/common';
import { DatabaseService } from '../database/database.service';
import { RedisService } from '../redis/redis.service';
import { RankCategory, RANKINGS } from '@perfect-world/shared';
import type { PaginatedResult, RankEntry } from '@perfect-world/shared';

@Injectable()
export class RankingService {
  constructor(
    private readonly db: DatabaseService,
    private readonly redis: RedisService,
  ) {}

  /**
   * Get paginated rankings for a category.
   * Uses Redis cache with 60s TTL.
   */
  async getRankings(
    category: RankCategory,
    page: number,
    limit: number = RANKINGS.PAGE_SIZE,
  ): Promise<PaginatedResult<RankEntry>> {
    const cacheKey = `rankings:${category}:${page}:${limit}`;

    // Check cache first
    const cached = await this.redis.getJson<PaginatedResult<RankEntry>>(cacheKey);
    if (cached) return cached;

    // Compute rankings from source data
    const allEntries = await this.computeRankings(category);

    // Paginate
    const result = this.paginate(allEntries, page, limit);

    // Cache result
    await this.redis.setJson(cacheKey, result, RANKINGS.CACHE_TTL_SECONDS);

    return result;
  }

  /**
   * Get top N entries for a category (used for homepage preview).
   * Uses Redis cache with 60s TTL.
   */
  async getTopN(category: RankCategory, n: number = RANKINGS.HOMEPAGE_TOP_N): Promise<RankEntry[]> {
    const cacheKey = `rankings:top:${category}:${n}`;

    // Check cache first
    const cached = await this.redis.getJson<RankEntry[]>(cacheKey);
    if (cached) return cached;

    // Compute rankings and take top N
    const allEntries = await this.computeRankings(category);
    const topN = allEntries.slice(0, n);

    // Cache result
    await this.redis.setJson(cacheKey, topN, RANKINGS.CACHE_TTL_SECONDS);

    return topN;
  }

  /**
   * Compute rankings for a category from the database.
   * Sorts by primary score descending, then tiebreaker descending.
   * Assigns tied rank positions (same rank, skip subsequent).
   */
  async computeRankings(category: RankCategory): Promise<RankEntry[]> {
    // Fetch raw data based on category
    const rawEntries = await this.fetchRawEntries(category);

    // Sort: primary score descending, tiebreaker descending
    const sorted = this.sortEntries(rawEntries);

    // Assign ranks with tied position handling
    return this.assignRanks(sorted, category);
  }

  /**
   * Sort entries by score descending, then tiebreaker descending.
   */
  sortEntries(entries: RawRankEntry[]): RawRankEntry[] {
    return [...entries].sort((a, b) => {
      // Primary: score descending
      if (b.score !== a.score) {
        return b.score > a.score ? 1 : -1;
      }
      // Tiebreaker: descending
      if (b.tiebreaker !== a.tiebreaker) {
        return b.tiebreaker > a.tiebreaker ? 1 : -1;
      }
      return 0;
    });
  }

  /**
   * Assign rank positions with tied rank handling.
   * Entries with same score AND same tiebreaker get the same rank.
   * Next distinct entry gets rank = previous rank + count of tied entries.
   */
  assignRanks(sorted: RawRankEntry[], category: RankCategory): RankEntry[] {
    if (sorted.length === 0) return [];

    const result: RankEntry[] = [];
    let currentRank = 1;

    for (let i = 0; i < sorted.length; i++) {
      if (i > 0) {
        const prev = sorted[i - 1];
        const curr = sorted[i];
        // If different from previous, assign new rank = position (1-indexed)
        if (curr.score !== prev.score || curr.tiebreaker !== prev.tiebreaker) {
          currentRank = i + 1;
        }
        // If same score and tiebreaker, keep currentRank unchanged (tied)
      }

      result.push({
        rank: currentRank,
        entityId: sorted[i].entityId,
        entityName: sorted[i].entityName,
        score: Number(sorted[i].score),
        tiebreaker: Number(sorted[i].tiebreaker),
        category,
        metadata: sorted[i].metadata,
      });
    }

    return result;
  }

  /**
   * Paginate a list of entries.
   */
  paginate<T>(entries: T[], page: number, pageSize: number): PaginatedResult<T> {
    const total = entries.length;
    const totalPages = Math.max(1, Math.ceil(total / pageSize));
    const safePage = Math.max(1, Math.min(page, totalPages));
    const start = (safePage - 1) * pageSize;
    const end = start + pageSize;

    return {
      data: entries.slice(start, end),
      total,
      page: safePage,
      pageSize,
      totalPages,
    };
  }

  /**
   * Fetch raw ranking entries from the database based on category.
   */
  private async fetchRawEntries(category: RankCategory): Promise<RawRankEntry[]> {
    switch (category) {
      case RankCategory.TOP_PLAYERS:
        return this.fetchTopPlayers();
      case RankCategory.TOP_GUILDS:
        return this.fetchTopGuilds();
      case RankCategory.TOP_PVP:
        return this.fetchTopPvP();
      case RankCategory.TOP_ECONOMY:
        return this.fetchTopEconomy();
      default:
        return [];
    }
  }

  private async fetchTopPlayers(): Promise<RawRankEntry[]> {
    const characters = await this.db.character.findMany({
      select: {
        id: true,
        name: true,
        level: true,
        experience: true,
        guild: { select: { name: true } },
      },
      orderBy: [{ level: 'desc' }, { experience: 'desc' }],
    });

    return characters.map((c) => ({
      entityId: c.id,
      entityName: c.name,
      score: BigInt(c.level),
      tiebreaker: c.experience,
      metadata: {
        guildAffiliation: c.guild?.name ?? 'No Guild',
      },
    }));
  }

  private async fetchTopGuilds(): Promise<RawRankEntry[]> {
    const guilds = await this.db.guild.findMany({
      select: {
        id: true,
        name: true,
        memberCount: true,
        _count: { select: { territories: true } },
      },
    });

    return guilds.map((g) => ({
      entityId: g.id,
      entityName: g.name,
      score: BigInt(g._count.territories),
      tiebreaker: BigInt(g.memberCount),
      metadata: null,
    }));
  }

  private async fetchTopPvP(): Promise<RawRankEntry[]> {
    const characters = await this.db.character.findMany({
      select: {
        id: true,
        name: true,
        arenaRating: true,
        kills: true,
        deaths: true,
        guild: { select: { name: true } },
      },
      orderBy: [{ arenaRating: 'desc' }],
    });

    return characters.map((c) => {
      // Kill/death ratio as tiebreaker (multiplied by 100 for precision)
      const kdRatio = c.deaths === 0 ? c.kills * 100 : Math.round((c.kills / c.deaths) * 100);
      return {
        entityId: c.id,
        entityName: c.name,
        score: BigInt(c.arenaRating),
        tiebreaker: BigInt(kdRatio),
        metadata: {
          guildAffiliation: c.guild?.name ?? 'No Guild',
          kills: c.kills,
          deaths: c.deaths,
        },
      };
    });
  }

  private async fetchTopEconomy(): Promise<RawRankEntry[]> {
    const characters = await this.db.character.findMany({
      select: {
        id: true,
        name: true,
        currency: true,
        guild: { select: { name: true } },
      },
      orderBy: [{ currency: 'desc' }],
    });

    return characters.map((c) => ({
      entityId: c.id,
      entityName: c.name,
      score: BigInt(Math.floor(Number(c.currency))),
      tiebreaker: BigInt(0),
      metadata: {
        guildAffiliation: c.guild?.name ?? 'No Guild',
      },
    }));
  }
}

/**
 * Internal raw entry before rank assignment.
 */
interface RawRankEntry {
  entityId: string;
  entityName: string;
  score: bigint;
  tiebreaker: bigint;
  metadata: Record<string, unknown> | null;
}

import { Controller, Get, Query, BadRequestException } from '@nestjs/common';
import { RankingService } from './ranking.service';
import { RankCategory, RANKINGS } from '@perfect-world/shared';
import type { PaginatedResult, RankEntry } from '@perfect-world/shared';

@Controller('rankings')
export class RankingController {
  constructor(private readonly rankingService: RankingService) {}

  /**
   * GET /rankings?category=TOP_PLAYERS&page=1
   * Returns paginated rankings for a category (100 entries/page).
   */
  @Get()
  async getRankings(
    @Query('category') category?: string,
    @Query('page') pageStr?: string,
  ): Promise<PaginatedResult<RankEntry>> {
    const validCategory = this.parseCategory(category);
    const page = this.parsePage(pageStr);

    return this.rankingService.getRankings(validCategory, page, RANKINGS.PAGE_SIZE);
  }

  /**
   * GET /rankings/top?category=TOP_PLAYERS&n=10
   * Returns top N entries for a category (used for homepage preview).
   */
  @Get('top')
  async getTopN(
    @Query('category') category?: string,
    @Query('n') nStr?: string,
  ): Promise<RankEntry[]> {
    const validCategory = this.parseCategory(category);
    const n = this.parseN(nStr);

    return this.rankingService.getTopN(validCategory, n);
  }

  private parseCategory(category?: string): RankCategory {
    if (!category) {
      throw new BadRequestException('category query parameter is required');
    }

    const validCategories = Object.values(RankCategory);
    if (!validCategories.includes(category as RankCategory)) {
      throw new BadRequestException(
        `Invalid category. Must be one of: ${validCategories.join(', ')}`,
      );
    }

    return category as RankCategory;
  }

  private parsePage(pageStr?: string): number {
    if (!pageStr) return 1;
    const page = parseInt(pageStr, 10);
    if (isNaN(page) || page < 1) return 1;
    return page;
  }

  private parseN(nStr?: string): number {
    if (!nStr) return RANKINGS.HOMEPAGE_TOP_N;
    const n = parseInt(nStr, 10);
    if (isNaN(n) || n < 1) return RANKINGS.HOMEPAGE_TOP_N;
    // Cap at page size to prevent abuse
    return Math.min(n, RANKINGS.PAGE_SIZE);
  }
}

import { Module } from '@nestjs/common';
import { RankingController } from './ranking.controller';
import { RankingService } from './ranking.service';

@Module({
  controllers: [RankingController],
  providers: [RankingService],
  exports: [RankingService],
})
export class RankingModule {}

import { describe, it, expect } from 'vitest';
import fc from 'fast-check';
import { RankCategory, RANKINGS } from '@perfect-world/shared';
import { RankingService } from './ranking.service';

/**
 * Property-Based Tests for Ranking Service
 *
 * Validates: Requirements 6.1, 6.7, 6.6
 */

// ─── Helpers / Arbitraries ────────────────────────────────────────────

/** The ranking service instance (we only use pure methods) */
const service = Object.create(RankingService.prototype) as RankingService;

/** Generate a RawRankEntry with bigint score and tiebreaker */
const rawRankEntryArb = fc.record({
  entityId: fc.uuid(),
  entityName: fc.string({ minLength: 1, maxLength: 30 }),
  score: fc.bigInt({ min: 0n, max: 1_000_000n }),
  tiebreaker: fc.bigInt({ min: 0n, max: 1_000_000n }),
  metadata: fc.constant(null),
});

/** Generate a list of RawRankEntries */
const rawRankEntryListArb = fc.array(rawRankEntryArb, { minLength: 0, maxLength: 200 });

/** Generate a non-empty list of RawRankEntries */
const nonEmptyRawRankEntryListArb = fc.array(rawRankEntryArb, { minLength: 1, maxLength: 200 });

/** Generate a RankCategory */
const rankCategoryArb = fc.constantFrom(
  RankCategory.TOP_PLAYERS,
  RankCategory.TOP_GUILDS,
  RankCategory.TOP_PVP,
  RankCategory.TOP_ECONOMY,
);

// ─── Property 8: Ranking Sort Order Correctness ───────────────────────

describe('Feature: perfect-world-neo-brutalism, Property 8: Ranking Sort Order Correctness', () => {
  /**
   * **Validates: Requirements 6.1**
   *
   * For any list of entities within a ranking category, the ranking function
   * SHALL produce a list sorted by primary score descending, then by tiebreaker
   * value descending, such that for any two adjacent entries (rank i, rank i+1),
   * entry i has a score >= entry i+1, and if scores are equal, entry i has
   * tiebreaker >= entry i+1.
   */

  it('sorted entries are in descending order by score, then tiebreaker', () => {
    fc.assert(
      fc.property(nonEmptyRawRankEntryListArb, (entries) => {
        const sorted = service.sortEntries(entries);

        // Verify descending order for all adjacent pairs
        for (let i = 0; i < sorted.length - 1; i++) {
          const current = sorted[i];
          const next = sorted[i + 1];

          // Primary score must be >= next
          expect(current.score >= next.score).toBe(true);

          // If scores are equal, tiebreaker must be >= next
          if (current.score === next.score) {
            expect(current.tiebreaker >= next.tiebreaker).toBe(true);
          }
        }
      }),
      { numRuns: 200 },
    );
  });

  it('sorting preserves all original entries (no entries lost or duplicated)', () => {
    fc.assert(
      fc.property(rawRankEntryListArb, (entries) => {
        const sorted = service.sortEntries(entries);

        // Same length
        expect(sorted.length).toBe(entries.length);

        // All original entity IDs are present
        const originalIds = entries.map((e) => e.entityId).sort();
        const sortedIds = sorted.map((e) => e.entityId).sort();
        expect(sortedIds).toEqual(originalIds);
      }),
      { numRuns: 200 },
    );
  });

  it('sorting does not mutate the original array', () => {
    fc.assert(
      fc.property(rawRankEntryListArb, (entries) => {
        const originalCopy = entries.map((e) => ({ ...e }));
        service.sortEntries(entries);

        // Original array should be unchanged
        expect(entries).toEqual(originalCopy);
      }),
      { numRuns: 200 },
    );
  });
});

// ─── Property 9: Tied Rank Position Assignment ────────────────────────

describe('Feature: perfect-world-neo-brutalism, Property 9: Tied Rank Position Assignment', () => {
  /**
   * **Validates: Requirements 6.7**
   *
   * For any set of ranking entries where two or more entries share the same
   * score AND the same tiebreaker value, those entries SHALL be assigned the
   * same rank position, and the next distinct entry SHALL receive a rank
   * position equal to the tied rank plus the count of tied entries (dense
   * ranking with gaps).
   */

  it('entries with same score AND tiebreaker get the same rank', () => {
    fc.assert(
      fc.property(nonEmptyRawRankEntryListArb, rankCategoryArb, (entries, category) => {
        const sorted = service.sortEntries(entries);
        const ranked = service.assignRanks(sorted, category);

        // For any two entries with same score and tiebreaker, rank must be equal
        for (let i = 0; i < ranked.length; i++) {
          for (let j = i + 1; j < ranked.length; j++) {
            if (ranked[i].score === ranked[j].score && ranked[i].tiebreaker === ranked[j].tiebreaker) {
              expect(ranked[i].rank).toBe(ranked[j].rank);
            }
          }
        }
      }),
      { numRuns: 200 },
    );
  });

  it('next distinct entry after a tie gets rank = position (1-indexed)', () => {
    fc.assert(
      fc.property(nonEmptyRawRankEntryListArb, rankCategoryArb, (entries, category) => {
        const sorted = service.sortEntries(entries);
        const ranked = service.assignRanks(sorted, category);

        // For each entry, if it differs from the previous, its rank = its 1-indexed position
        for (let i = 1; i < ranked.length; i++) {
          const prev = ranked[i - 1];
          const curr = ranked[i];

          if (curr.score !== prev.score || curr.tiebreaker !== prev.tiebreaker) {
            // This is a distinct entry; rank should equal position (i + 1)
            expect(curr.rank).toBe(i + 1);
          }
        }
      }),
      { numRuns: 200 },
    );
  });

  it('first entry always has rank 1', () => {
    fc.assert(
      fc.property(nonEmptyRawRankEntryListArb, rankCategoryArb, (entries, category) => {
        const sorted = service.sortEntries(entries);
        const ranked = service.assignRanks(sorted, category);

        expect(ranked[0].rank).toBe(1);
      }),
      { numRuns: 200 },
    );
  });

  it('ranks are non-decreasing', () => {
    fc.assert(
      fc.property(nonEmptyRawRankEntryListArb, rankCategoryArb, (entries, category) => {
        const sorted = service.sortEntries(entries);
        const ranked = service.assignRanks(sorted, category);

        for (let i = 1; i < ranked.length; i++) {
          expect(ranked[i].rank).toBeGreaterThanOrEqual(ranked[i - 1].rank);
        }
      }),
      { numRuns: 200 },
    );
  });

  it('empty input produces empty output', () => {
    fc.assert(
      fc.property(rankCategoryArb, (category) => {
        const ranked = service.assignRanks([], category);
        expect(ranked).toEqual([]);
      }),
      { numRuns: 10 },
    );
  });
});

// ─── Property 11: Pagination Correctness ──────────────────────────────

describe('Feature: perfect-world-neo-brutalism, Property 11: Pagination Correctness', () => {
  /**
   * **Validates: Requirements 6.6**
   *
   * For any total entry count N and page size P, the pagination function SHALL
   * produce exactly ceil(N/P) pages, each page (except possibly the last)
   * containing exactly P entries, and the last page containing between 1 and P
   * entries inclusive.
   */

  /** Generate a list of generic items for pagination testing */
  const itemListArb = fc.array(fc.integer(), { minLength: 0, maxLength: 500 });

  /** Generate a valid page size (use the default 100 and also test other sizes) */
  const pageSizeArb = fc.integer({ min: 1, max: 200 });

  it('totalPages equals ceil(N/P) (minimum 1)', () => {
    fc.assert(
      fc.property(itemListArb, pageSizeArb, (items, pageSize) => {
        const result = service.paginate(items, 1, pageSize);

        const expectedTotalPages = Math.max(1, Math.ceil(items.length / pageSize));
        expect(result.totalPages).toBe(expectedTotalPages);
        expect(result.total).toBe(items.length);
      }),
      { numRuns: 200 },
    );
  });

  it('each full page contains exactly pageSize entries', () => {
    fc.assert(
      fc.property(
        fc.array(fc.integer(), { minLength: 1, maxLength: 500 }),
        pageSizeArb,
        (items, pageSize) => {
          const totalPages = Math.max(1, Math.ceil(items.length / pageSize));

          // Check all pages except the last
          for (let page = 1; page < totalPages; page++) {
            const result = service.paginate(items, page, pageSize);
            expect(result.data.length).toBe(pageSize);
          }
        },
      ),
      { numRuns: 200 },
    );
  });

  it('last page contains between 1 and pageSize entries (for non-empty input)', () => {
    fc.assert(
      fc.property(
        fc.array(fc.integer(), { minLength: 1, maxLength: 500 }),
        pageSizeArb,
        (items, pageSize) => {
          const totalPages = Math.max(1, Math.ceil(items.length / pageSize));
          const lastPage = service.paginate(items, totalPages, pageSize);

          expect(lastPage.data.length).toBeGreaterThanOrEqual(1);
          expect(lastPage.data.length).toBeLessThanOrEqual(pageSize);
        },
      ),
      { numRuns: 200 },
    );
  });

  it('all pages together contain all entries in order', () => {
    fc.assert(
      fc.property(
        fc.array(fc.integer(), { minLength: 0, maxLength: 300 }),
        pageSizeArb,
        (items, pageSize) => {
          const totalPages = Math.max(1, Math.ceil(items.length / pageSize));
          const allData: number[] = [];

          for (let page = 1; page <= totalPages; page++) {
            const result = service.paginate(items, page, pageSize);
            allData.push(...result.data);
          }

          expect(allData).toEqual(items);
        },
      ),
      { numRuns: 200 },
    );
  });

  it('page metadata is correct', () => {
    fc.assert(
      fc.property(
        itemListArb,
        pageSizeArb,
        fc.integer({ min: 1, max: 50 }),
        (items, pageSize, requestedPage) => {
          const result = service.paginate(items, requestedPage, pageSize);

          // Page is clamped to valid range
          const totalPages = Math.max(1, Math.ceil(items.length / pageSize));
          const expectedPage = Math.max(1, Math.min(requestedPage, totalPages));

          expect(result.page).toBe(expectedPage);
          expect(result.pageSize).toBe(pageSize);
          expect(result.total).toBe(items.length);
          expect(result.totalPages).toBe(totalPages);
        },
      ),
      { numRuns: 200 },
    );
  });

  it('empty input produces one page with empty data', () => {
    fc.assert(
      fc.property(pageSizeArb, (pageSize) => {
        const result = service.paginate([], 1, pageSize);

        expect(result.data).toEqual([]);
        expect(result.total).toBe(0);
        expect(result.page).toBe(1);
        expect(result.totalPages).toBe(1);
      }),
      { numRuns: 50 },
    );
  });

  it('default page size of 100 entries per page works correctly', () => {
    fc.assert(
      fc.property(
        fc.array(fc.integer(), { minLength: 101, maxLength: 500 }),
        (items) => {
          const result = service.paginate(items, 1, RANKINGS.PAGE_SIZE);

          expect(result.data.length).toBe(RANKINGS.PAGE_SIZE);
          expect(result.pageSize).toBe(100);
        },
      ),
      { numRuns: 50 },
    );
  });
});

import { describe, it, expect, beforeEach, vi } from 'vitest';
import { RankingService } from './ranking.service';
import { RankCategory } from '@perfect-world/shared';

// Mock dependencies
const mockDb = {
  character: { findMany: vi.fn() },
  guild: { findMany: vi.fn() },
};

const mockRedis = {
  getJson: vi.fn(),
  setJson: vi.fn(),
};

describe('RankingService', () => {
  let service: RankingService;

  beforeEach(() => {
    vi.clearAllMocks();
    service = new RankingService(mockDb as any, mockRedis as any);
  });

  describe('sortEntries', () => {
    it('should sort by score descending', () => {
      const entries = [
        { entityId: '1', entityName: 'A', score: 10n, tiebreaker: 0n, metadata: null },
        { entityId: '2', entityName: 'B', score: 30n, tiebreaker: 0n, metadata: null },
        { entityId: '3', entityName: 'C', score: 20n, tiebreaker: 0n, metadata: null },
      ];

      const sorted = service.sortEntries(entries);

      expect(sorted[0].entityName).toBe('B');
      expect(sorted[1].entityName).toBe('C');
      expect(sorted[2].entityName).toBe('A');
    });

    it('should use tiebreaker descending when scores are equal', () => {
      const entries = [
        { entityId: '1', entityName: 'A', score: 10n, tiebreaker: 5n, metadata: null },
        { entityId: '2', entityName: 'B', score: 10n, tiebreaker: 15n, metadata: null },
        { entityId: '3', entityName: 'C', score: 10n, tiebreaker: 10n, metadata: null },
      ];

      const sorted = service.sortEntries(entries);

      expect(sorted[0].entityName).toBe('B');
      expect(sorted[1].entityName).toBe('C');
      expect(sorted[2].entityName).toBe('A');
    });

    it('should handle empty array', () => {
      const sorted = service.sortEntries([]);
      expect(sorted).toEqual([]);
    });
  });

  describe('assignRanks', () => {
    it('should assign sequential ranks for distinct entries', () => {
      const sorted = [
        { entityId: '1', entityName: 'A', score: 30n, tiebreaker: 10n, metadata: null },
        { entityId: '2', entityName: 'B', score: 20n, tiebreaker: 5n, metadata: null },
        { entityId: '3', entityName: 'C', score: 10n, tiebreaker: 1n, metadata: null },
      ];

      const ranked = service.assignRanks(sorted, RankCategory.TOP_PLAYERS);

      expect(ranked[0].rank).toBe(1);
      expect(ranked[1].rank).toBe(2);
      expect(ranked[2].rank).toBe(3);
    });

    it('should assign same rank for tied entries and skip subsequent', () => {
      const sorted = [
        { entityId: '1', entityName: 'A', score: 30n, tiebreaker: 10n, metadata: null },
        { entityId: '2', entityName: 'B', score: 20n, tiebreaker: 5n, metadata: null },
        { entityId: '3', entityName: 'C', score: 20n, tiebreaker: 5n, metadata: null },
        { entityId: '4', entityName: 'D', score: 10n, tiebreaker: 1n, metadata: null },
      ];

      const ranked = service.assignRanks(sorted, RankCategory.TOP_PLAYERS);

      expect(ranked[0].rank).toBe(1);
      expect(ranked[1].rank).toBe(2); // B tied with C
      expect(ranked[2].rank).toBe(2); // C tied with B
      expect(ranked[3].rank).toBe(4); // D skips rank 3
    });

    it('should handle all entries tied', () => {
      const sorted = [
        { entityId: '1', entityName: 'A', score: 10n, tiebreaker: 5n, metadata: null },
        { entityId: '2', entityName: 'B', score: 10n, tiebreaker: 5n, metadata: null },
        { entityId: '3', entityName: 'C', score: 10n, tiebreaker: 5n, metadata: null },
      ];

      const ranked = service.assignRanks(sorted, RankCategory.TOP_PLAYERS);

      expect(ranked[0].rank).toBe(1);
      expect(ranked[1].rank).toBe(1);
      expect(ranked[2].rank).toBe(1);
    });

    it('should handle empty array', () => {
      const ranked = service.assignRanks([], RankCategory.TOP_PLAYERS);
      expect(ranked).toEqual([]);
    });

    it('should handle multiple tie groups', () => {
      const sorted = [
        { entityId: '1', entityName: 'A', score: 30n, tiebreaker: 10n, metadata: null },
        { entityId: '2', entityName: 'B', score: 30n, tiebreaker: 10n, metadata: null },
        { entityId: '3', entityName: 'C', score: 20n, tiebreaker: 5n, metadata: null },
        { entityId: '4', entityName: 'D', score: 20n, tiebreaker: 5n, metadata: null },
        { entityId: '5', entityName: 'E', score: 10n, tiebreaker: 1n, metadata: null },
      ];

      const ranked = service.assignRanks(sorted, RankCategory.TOP_PVP);

      expect(ranked[0].rank).toBe(1);
      expect(ranked[1].rank).toBe(1);
      expect(ranked[2].rank).toBe(3);
      expect(ranked[3].rank).toBe(3);
      expect(ranked[4].rank).toBe(5);
    });
  });

  describe('paginate', () => {
    it('should return correct page of entries', () => {
      const entries = Array.from({ length: 250 }, (_, i) => ({ id: i }));

      const page1 = service.paginate(entries, 1, 100);
      expect(page1.data.length).toBe(100);
      expect(page1.total).toBe(250);
      expect(page1.page).toBe(1);
      expect(page1.pageSize).toBe(100);
      expect(page1.totalPages).toBe(3);

      const page3 = service.paginate(entries, 3, 100);
      expect(page3.data.length).toBe(50);
      expect(page3.page).toBe(3);
    });

    it('should handle page beyond total pages', () => {
      const entries = Array.from({ length: 50 }, (_, i) => ({ id: i }));

      const result = service.paginate(entries, 5, 100);
      expect(result.page).toBe(1); // Clamped to max valid page
      expect(result.data.length).toBe(50);
    });

    it('should handle empty entries', () => {
      const result = service.paginate([], 1, 100);
      expect(result.data).toEqual([]);
      expect(result.total).toBe(0);
      expect(result.totalPages).toBe(1);
      expect(result.page).toBe(1);
    });

    it('should handle page 0 or negative', () => {
      const entries = Array.from({ length: 50 }, (_, i) => ({ id: i }));

      const result = service.paginate(entries, 0, 100);
      expect(result.page).toBe(1);

      const result2 = service.paginate(entries, -1, 100);
      expect(result2.page).toBe(1);
    });
  });

  describe('getRankings (with cache)', () => {
    it('should return cached result if available', async () => {
      const cachedResult = {
        data: [{ rank: 1, entityId: '1', entityName: 'Test', score: 100, tiebreaker: 50, category: RankCategory.TOP_PLAYERS, metadata: null }],
        total: 1,
        page: 1,
        pageSize: 100,
        totalPages: 1,
      };
      mockRedis.getJson.mockResolvedValue(cachedResult);

      const result = await service.getRankings(RankCategory.TOP_PLAYERS, 1);

      expect(result).toEqual(cachedResult);
      expect(mockDb.character.findMany).not.toHaveBeenCalled();
    });

    it('should compute and cache when cache miss', async () => {
      mockRedis.getJson.mockResolvedValue(null);
      mockDb.character.findMany.mockResolvedValue([
        { id: '1', name: 'Player1', level: 50, experience: 1000n, guild: { name: 'TestGuild' } },
        { id: '2', name: 'Player2', level: 45, experience: 500n, guild: null },
      ]);

      const result = await service.getRankings(RankCategory.TOP_PLAYERS, 1);

      expect(result.data.length).toBe(2);
      expect(result.data[0].rank).toBe(1);
      expect(result.data[0].entityName).toBe('Player1');
      expect(result.data[1].rank).toBe(2);
      expect(mockRedis.setJson).toHaveBeenCalledWith(
        'rankings:TOP_PLAYERS:1:100',
        expect.any(Object),
        60,
      );
    });
  });

  describe('getTopN (with cache)', () => {
    it('should return cached result if available', async () => {
      const cached = [
        { rank: 1, entityId: '1', entityName: 'Test', score: 100, tiebreaker: 50, category: RankCategory.TOP_PLAYERS, metadata: null },
      ];
      mockRedis.getJson.mockResolvedValue(cached);

      const result = await service.getTopN(RankCategory.TOP_PLAYERS, 10);

      expect(result).toEqual(cached);
      expect(mockDb.character.findMany).not.toHaveBeenCalled();
    });

    it('should compute and return top N entries', async () => {
      mockRedis.getJson.mockResolvedValue(null);
      const characters = Array.from({ length: 20 }, (_, i) => ({
        id: `${i}`,
        name: `Player${i}`,
        level: 50 - i,
        experience: BigInt(1000 - i * 10),
        guild: null,
      }));
      mockDb.character.findMany.mockResolvedValue(characters);

      const result = await service.getTopN(RankCategory.TOP_PLAYERS, 10);

      expect(result.length).toBe(10);
      expect(result[0].entityName).toBe('Player0');
      expect(result[9].entityName).toBe('Player9');
    });
  });
});

